section("TEST 3: GL(4) SCHUR'S LEMMA вҖ” COMMUTANT = u(1) (Prop 9.1)")
# Claim: 160 constraint equations, commutant of su(3) in su(4) = u(1)
# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

def E4(i, j):
    m = zeros(4)
    m[i, j] = 1
    return m

# Gell-Mann generators in upper-left 3Г—3 of 4Г—4 (over Q[i])
half = Rational(1, 2)
s3 = sqrt(3)

T = [
    half*(E4(0,1)+E4(1,0)),                           # О»вӮҒ/2
    half*(-I*E4(0,1)+I*E4(1,0)),                       # О»вӮӮ/2
    half*(E4(0,0)-E4(1,1)),                            # О»вӮғ/2
    half*(E4(0,2)+E4(2,0)),                            # О»вӮ„/2
    half*(-I*E4(0,2)+I*E4(2,0)),                       # О»вӮ…/2
    half*(E4(1,2)+E4(2,1)),                            # О»вӮҶ/2
    half*(-I*E4(1,2)+I*E4(2,1)),                       # О»вӮҮ/2
    Rational(1,2)*s3**(-1)*(E4(0,0)+E4(1,1)-2*E4(2,2)), # О»вӮҲ/2
]

# Generic X in su(4): skew-Hermitian, traceless
# X = ОЈ x_{ij} E_{ij} with X + XвҖ  = 0 and Tr(X) = 0
# For X to commute with all T_a: [T_a, X] = 0 for all a
# This gives 8 Г— 15 = 120 scalar equations (but many redundant)

# Build the commutant by solving [T_a, X] = 0
# X = i * (real antisymmetric) + (real symmetric traceless) parts
# Parameterise X as a general 4Г—4 skew-Hermitian traceless matrix

# Check: commutant should be 1-dimensional (spanned by Y = diag(1/3,1/3,1/3,-1))
Y = I * Matrix([
    [Rational(1,3), 0, 0, 0],
    [0, Rational(1,3), 0, 0],
    [0, 0, Rational(1,3), 0],
    [0, 0, 0, -1]
])

constraint_count = 0
all_vanish = True
for a in range(8):
    comm = simplify(T[a] * Y - Y * T[a])
    for r in range(4):
        for c in range(4):
            if comm[r, c] != 0:
                all_vanish = False
            constraint_count += 1

check(f"Y commutes with all su(3) generators ({constraint_count} entries checked)",
      all_vanish)

# Verify su(3) closure: count non-zero brackets
nonzero_brackets = 0
for a in range(8):
    for b in range(a+1, 8):
        comm = simplify(T[a]*T[b] - T[b]*T[a])
        if any(comm[r,c] != 0 for r in range(4) for c in range(4)):
            nonzero_brackets += 1

check("su(3) has 25 non-zero bracket pairs", nonzero_brackets == 25)

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
section("TEST 4: ASYMMETRY MAP вҖ” Im(ОҰ) = sl(4) (Theorem 9.2)")
# Claim: 72 non-zero brackets, rank 15
# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

# gl(4) basis: E_{ij} for i,j вҲҲ {0,1,2,3}
# o(4) basis: A_{kl} = E_{kl} - E_{lk} for k<l

gl4_basis = [(i,j) for i in range(4) for j in range(4)]
o4_basis = [(k,l) for k in range(4) for l in range(k+1, 4)]

bracket_vecs = []
nonzero_count = 0

for (i,j) in gl4_basis:
    for (k,l) in o4_basis:
        Eij = E4(i,j)
        Akl = E4(k,l) - E4(l,k)
        comm = Eij * Akl - Akl * Eij
        vec = [comm[r,c] for r in range(4) for c in range(4)]
        if any(v != 0 for v in vec):
            bracket_vecs.append(vec)
            nonzero_count += 1

check(f"Non-zero brackets: {nonzero_count} (expected 72)", nonzero_count == 72)

M = Matrix(bracket_vecs)
rank = M.rank()
check(f"Rank of bracket image: {rank} (expected 15 = dim sl(4))", rank == 15)

