def nearest_neighbour_matrix(m1, m2, m3):
    """Nearest-neighbour (Fritzsch) texture"""
    C12 = np.sqrt(m1 * m2)
    C23 = np.sqrt(m2 * m3)
    M = np.array([
        [0,    C12,  0],
        [C12,  m2,   C23],
        [0,    C23,  m3]
    ])
    return M

M_u = nearest_neighbour_matrix(m_u, m_c, m_t)
M_d = nearest_neighbour_matrix(m_d, m_s, m_b)

print(f"  Up mass matrix (nearest-neighbour):")
