# Step 2: Set О»(M_P) = 2вҲҡ3/27 (ACS prediction) and run DOWN
lam_ACS = 2*np.sqrt(3)/27
print(f"\n  ACS prediction: О»(M_P) = 2вҲҡ3/27 = {lam_ACS:.6f}")
print(f"  SM running gives: О»(M_P) = {lam_MP_sm:.6f}")
