y0_down = [g1_MP, g2_MP, g3_MP, yt_MP, lam_ACS]
sol_down = solve_ivp(sm_rge, [t_end, 0], y0_down, method='RK45', rtol=1e-10, max_step=0.5)
lam_MZ_pred = sol_down.y[4, -1]

print(f"\n  О»(M_Z) from ACS via RG running: {lam_MZ_pred:.6f}")
