mH_pred = np.sqrt(2*lam_MZ_pred) * 246.22
print(f"  m_H predicted: {mH_pred:.1f} GeV (observed: 125.25 GeV)")

# The issue: О» runs VERY steeply near the Planck scale
# Let's check what О»(M_P) the SM needs to land on 0.1294 at M_Z
print(f"\n  Note: SM О» runs to {lam_MP_sm:.4f} at M_P.")
print(f"  The ACS value 0.1283 is {'above' if lam_ACS > lam_MP_sm else 'below'} the SM trajectory.")
print(f"  The RG running of О» over 17 decades is dominated by the top Yukawa.")
