fig, ax = plt.subplots(figsize=(4.0, 2.8))

gammas = np.linspace(0.05, 0.8, 200)

def Z_SU2(gamma):
    Z = 0.0
    j = 0.5
    while j <= 50:
        Z += (2*j + 1) * np.exp(-2 * np.pi * gamma * np.sqrt(j * (j + 1)))
        j += 0.5
    return Z

Z_vals = [Z_SU2(g) for g in gammas]

ax.plot(gammas, Z_vals, 'b-', linewidth=1.5, label='$Z(\\gamma)$')
