fig, ax = plt.subplots(figsize=(4.2, 2.5))

configs = ['Uncoupled', 'Symmetric\n$(f{=}g)$', 'Asymmetric\n$(f{=}x^2, g{=}|x{-}8|)$', 'Swapped\n$(f{=}|x{-}8|, g{=}x^2)$']
