#!/usr/bin/env python3
"""
GL(4) Asymmetry Map: What Does [e, Пү] Generate?
=================================================
The "~10-page Lie theory computation" from Conjecture 9.6.

Question: For the vierbein e and connection Пү on Y^14,
what is the image of the asymmetry map ОҰ(v) = [e(v), Пү(v)]?

Theorem 9.2 showed Im(ОҰ) = sl(4) for GENERIC (e, Пү).
But the physical question is: what happens when (e, Пү) are
CONSTRAINED by the Palatini structure?

Specifically:
- e^a_Ој is vierbein-compatible (invertible, gives metric)
- Пү^{ab}_Ој is a Lorentz connection (antisymmetric in ab)
- After vacuum selection: residual O(4) symmetry

This computation determines the CONSTRAINED image.

ALL arithmetic exact: symbolic over Q.
"""

from sympy import (
    Matrix, I, Rational, zeros, eye, simplify, expand,
    symbols, sqrt, pprint, BlockMatrix, Symbol, Trace
)
import itertools

print("=" * 70)
print("GL(4) ASYMMETRY MAP COMPUTATION")
print("What subalgebra does [e, Пү] generate?")
print("=" * 70)

# в”Җв”Җв”Җ Step 1: Parameterize the vierbein в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

print(f"\nв”Җв”Җ Step 1: Vierbein structure в”Җв”Җ")

# The vierbein e^a_Ој is a 4Г—4 invertible matrix
# At the vacuum: e^a_Ој = Оҙ^a_Ој (flat spacetime)
# Perturbation: e^a_Ој = Оҙ^a_Ој + Оө h^a_Ој
# The perturbation h^a_Ој is a general 4Г—4 matrix (16 components)

# Under O(4) = SU(2)_L Г— SU(2)_R / Z_2:
# h^a_Ој transforms as (2,2) of SU(2)_L Г— SU(2)_R

# The 16 components of h^a_Ој split under O(4) as:
# Symmetric traceless (9) + antisymmetric (6) + trace (1)
# = metric perturbation + Lorentz rotation + conformal factor

print(f"   Vacuum vierbein: e^a_Ој = Оҙ^a_Ој")
print(f"   Perturbation: h^a_Ој has 16 components")
print(f"   Under O(4): 16 = 10 (symmetric) + 6 (antisymmetric)")

# в”Җв”Җв”Җ Step 2: Parameterize the connection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

print(f"\nв”Җв”Җ Step 2: Connection structure в”Җв”Җ")

# The spin connection Пү^{ab}_Ој is antisymmetric in (a,b)
# So it has 6 Г— 4 = 24 components (but only 24 independent)
# Actually: Пү^{ab}_Ој with a<b gives 6 choices, times 4 for Ој = 24

# Under O(4): the connection decomposes as
# Пү вҲҲ (3,1) вҠ• (1,3) of SU(2)_L Г— SU(2)_R

# At the vacuum, Пү = 0 (flat space, no curvature)
# Perturbation: Пү^{ab}_Ој = Оө ПүМғ^{ab}_Ој

print(f"   Vacuum connection: Пү^{{ab}}_Ој = 0")
print(f"   Perturbation: 6 Г— 4 = 24 components")
print(f"   Under O(4): (3,1) вҠ• (1,3)")

# в”Җв”Җв”Җ Step 3: The bracket [e, Пү] in GL(4) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

print(f"\nв”Җв”Җ Step 3: Computing the bracket [e, Пү] в”Җв”Җ")
print(f"   The bracket lives in gl(4) = End(RвҒҙ)")
print("   [e, omega]^a_b = e^a_mu omega^mu_b - omega^a_mu e^mu_b")

# For a generic vierbein perturbation h and connection perturbation ПүМғ:
# [h, ПүМғ]^a_b = h^a_Ој ПүМғ^Ој_b - ПүМғ^a_Ој h^Ој_b

# Let's work with explicit 4Г—4 matrices
# h = general 4Г—4 (vierbein perturbation)
# ПүМғ = antisymmetric 4Г—4 (connection perturbation, for fixed Ој)

# The key question: as h ranges over all 4Г—4 matrices
# and ПүМғ ranges over all antisymmetric 4Г—4 matrices,
# what is the span of [h, ПүМғ] = hВ·ПүМғ - ПүМғВ·h ?

# Parameterize h with 16 symbols
h_params = symbols('h0:16', real=True)
h = Matrix(4, 4, h_params)

# Parameterize ПүМғ antisymmetric: 6 independent parameters
w_params = symbols('w0:6', real=True)
omega = Matrix([
    [0,          w_params[0], w_params[1], w_params[2]],
    [-w_params[0], 0,          w_params[3], w_params[4]],
    [-w_params[1], -w_params[3], 0,          w_params[5]],
    [-w_params[2], -w_params[4], -w_params[5], 0         ]
])

# Compute the commutator
bracket = h * omega - omega * h
bracket = expand(bracket)

print(f"   Bracket computed: 4Г—4 matrix with 16 entries")
print(f"   Each entry is linear in h-params and w-params")

# в”Җв”Җв”Җ Step 4: Determine the image в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

print(f"\nв”Җв”Җ Step 4: Span of [h, ПүМғ] as h, ПүМғ vary в”Җв”Җ")

# Extract the 16 entries of the bracket as linear forms in the 22 parameters
all_params = list(h_params) + list(w_params)

# Build the coefficient matrix: each row is one (h,w) parameter pair,
# each column is one entry of the bracket
# Actually: the bracket entries are BILINEAR in (h, w)
# So we need to look at all products h_i * w_j

# The image of the map (h, ПүМғ) вҶ’ [h, ПүМғ] is a linear subspace of gl(4)
# whose dimension we want to find.

# Since the map is bilinear, the image is spanned by all
# [E_{ij}, A_{kl}] where E_{ij} = basis matrix, A_{kl} = basis antisymmetric

# Basis for 4Г—4: E_{ij} has 1 at (i,j), 0 elsewhere
# Basis for antisymmetric: A_{kl} = E_{kl} - E_{lk} for k < l

print(f"   Computing all basis brackets [E_{{ij}}, A_{{kl}}]...")

image_vectors = []

for i in range(4):
    for j in range(4):
        # Basis vierbein perturbation E_{ij}
        E = zeros(4)
        E[i, j] = 1
        
        for k in range(4):
            for l in range(k+1, 4):
                # Basis antisymmetric A_{kl}
                A = zeros(4)
                A[k, l] = 1
                A[l, k] = -1
                
                # Commutator
                comm = E * A - A * E
                
                # Flatten to 16-vector
                vec = [comm[r, c] for r in range(4) for c in range(4)]
                
                if any(v != 0 for v in vec):
                    image_vectors.append(vec)

print(f"   Total non-zero basis brackets: {len(image_vectors)}")

# Find rank of the image (= dimension of generated subalgebra)
from sympy import Matrix as SympyMatrix

if image_vectors:
    M = SympyMatrix(image_vectors)
    rank = M.rank()
    print(f"   Rank of image matrix: {rank}")
    print(f"   dim(gl(4)) = 16, dim(sl(4)) = 15")
    print(f"   Image dimension: {rank}")

# в”Җв”Җв”Җ Step 5: Check if image is contained in sl(4) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

print(f"\nв”Җв”Җ Step 5: Is the image traceless? в”Җв”Җ")

all_traceless = True
for vec in image_vectors:
    # Trace = sum of diagonal entries: vec[0] + vec[5] + vec[10] + vec[15]
    tr = vec[0] + vec[5] + vec[10] + vec[15]
    if tr != 0:
        all_traceless = False
        break

print(f"   All brackets traceless: {all_traceless}")
if all_traceless:
    print(f"   вң“ Image вҠҶ sl(4)")
    if rank == 15:
        print(f"   вң“ Image = sl(4) (dimension 15 = dim(sl(4)))")
    elif rank < 15:
        print(f"   Image is PROPER SUBALGEBRA of sl(4), dimension {rank}")

# в”Җв”Җв”Җ Step 6: Now constrain to PHYSICAL vierbein в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

print(f"\nв”Җв”Җ Step 6: Physical constraint вҖ” symmetric vierbein perturbation в”Җв”Җ")
print(f"   In Palatini gravity, the vierbein gives metric:")
print("   g_uv = eta_ab e^a_u e^b_v")
print(f"   Perturbation of metric: Оҙg ~ h + h^T (symmetric part)")
print(f"   The antisymmetric part of h is a local Lorentz transformation")
print(f"   ")
print(f"   Physical DOF: h_(ab) = 10 (symmetric) вҖ” metric perturbation")
print("   Gauge DOF: h_[ab] = 6 (antisymmetric) -- Lorentz rotation")

# Constrain h to be SYMMETRIC (physical metric perturbation only)
image_symmetric = []

for i in range(4):
    for j in range(i, 4):  # Only i вүӨ j (symmetric)
        # Symmetric basis: E_{ij} + E_{ji} (or just E_{ii} for diagonal)
        E = zeros(4)
        if i == j:
            E[i, j] = 1
        else:
            E[i, j] = 1
            E[j, i] = 1
        
        for k in range(4):
            for l in range(k+1, 4):
                A = zeros(4)
                A[k, l] = 1
                A[l, k] = -1
                
                comm = E * A - A * E
                vec = [comm[r, c] for r in range(4) for c in range(4)]
                
                if any(v != 0 for v in vec):
                    image_symmetric.append(vec)

M_sym = SympyMatrix(image_symmetric)
rank_sym = M_sym.rank()
print(f"\n   With symmetric h only:")
print(f"   Non-zero brackets: {len(image_symmetric)}")
print(f"   Rank: {rank_sym}")

# в”Җв”Җв”Җ Step 7: Constrain to ANTISYMMETRIC h (Lorentz transformations) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

print(f"\nв”Җв”Җ Step 7: Gauge constraint вҖ” antisymmetric h (Lorentz rotations) в”Җв”Җ")

image_antisym = []

for i in range(4):
    for j in range(i+1, 4):  # Only i < j (antisymmetric)
        E = zeros(4)
        E[i, j] = 1
        E[j, i] = -1
        
        for k in range(4):
            for l in range(k+1, 4):
                A = zeros(4)
                A[k, l] = 1
                A[l, k] = -1
                
                comm = E * A - A * E
                vec = [comm[r, c] for r in range(4) for c in range(4)]
                
                if any(v != 0 for v in vec):
                    image_antisym.append(vec)

M_anti = SympyMatrix(image_antisym)
rank_anti = M_anti.rank()
print(f"   With antisymmetric h only:")
