print(f"   Rank: {rank_anti}")

# в”Җв”Җв”Җ Step 8: O(4) decomposition в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

print(f"\nв”Җв”Җ Step 8: Summary of image dimensions в”Җв”Җ")
print(f"   ")
print(f"   Generic h (all 16 DOF) + antisym Пү (6 DOF):")
print(f"     вҶ’ [h, ПүМғ] spans {rank}-dimensional subspace of gl(4)")
print(f"   ")
print(f"   Symmetric h (10 DOF) + antisym Пү (6 DOF):")
print(f"     вҶ’ [h, ПүМғ] spans {rank_sym}-dimensional subspace")
print(f"   ")
print(f"   Antisymmetric h (6 DOF) + antisym Пү (6 DOF):")
print(f"     вҶ’ [h, ПүМғ] spans {rank_anti}-dimensional subspace")
