print(f"   This is the LORENTZ SECTOR вҖ” should be o(4) = su(2)вҠ•su(2), dim 6")

# Check: is rank_anti = 6?
if rank_anti == 6:
    print(f"   вң“ CONFIRMED: [o(4), o(4)] = o(4), dimension 6")
    print(f"     This is the self-bracket of the connection.")
