# The symmetric-antisymmetric bracket [h_{{(ab)}}, Пү_{{[cd]}}]
# generates the MIXED sector вҖ” this is where new structure lives
image_mixed = []
for i in range(4):
    for j in range(i, 4):
        E = zeros(4)
        if i == j:
            E[i, j] = 1
        else:
            E[i, j] = 1
            E[j, i] = 1
        
        for k in range(4):
            for l in range(k+1, 4):
                A = zeros(4)
                A[k, l] = 1
                A[l, k] = -1
                
                comm = E * A - A * E
                vec = [comm[r, c] for r in range(4) for c in range(4)]
                
                if any(v != 0 for v in vec):
                    image_mixed.append(vec)

# Check what the mixed sector generates BEYOND the Lorentz sector
all_vecs = image_antisym + image_mixed
M_all = SympyMatrix(all_vecs)
rank_all = M_all.rank()

print(f"\n   Mixed sector [h_{{(ab)}}, Пү_{{[cd]}}]: spans {rank_sym}-dim space")
print(f"   Combined (Lorentz + mixed): spans {rank_all}-dim space")
print(f"   New directions from metric-connection bracket: {rank_all - rank_anti}")

# в”Җв”Җв”Җ Final summary в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

