A13 = np.zeros((4,4)); A13[1,3]=1; A13[3,1]=-1
A23 = np.zeros((4,4)); A23[2,3]=1; A23[3,2]=-1
g_phys = (A03 + A13 + A23) / np.sqrt(3)

