# A03 has entries (0,3) and (3,0). A13 has entries (1,3) and (3,1). No overlap.
# So ||A03+A13+A23||ВІ = 2 + 2 + 2 = 6, ||g|| = вҲҡ(6/3) = вҲҡ2.

print(f"\n  Exact values:")
print(f"    ||T_BL|| = вҲҡ(4/3) = {np.sqrt(4/3):.6f}, computed: {norm(T_BL):.6f}")
print(f"    ||g|| = вҲҡ2 = {np.sqrt(2):.6f}, computed: {norm(g_phys):.6f}")
print(f"    ||[f,g]|| = (4/3)вҲҡ2 = {(4/3)*np.sqrt(2):.6f}, computed: {norm(L2):.6f}")
