    ("вҲҡ(2)Г—(4/3)Г—вҲҡО»_W", np.sqrt(2)*(4/3)*np.sqrt(lambda_W)),
    ("2О»_W/вҲҡ(1/3)", 2*lambda_W/np.sqrt(1/3)),
    ("(4/3)ВІГ—О»_W", (4/3)**2*lambda_W),
    ("вҲҡ(8/3Г—О»_W)", np.sqrt(8/3*lambda_W)),
    ("2вҲҡ(2/3)Г—вҲҡО»_W", 2*np.sqrt(2/3)*np.sqrt(lambda_W)),
    ("4О»_W/вҲҡ3", 4*lambda_W/np.sqrt(3)),
    ("вҲҡ(2О»_W/вҲҡ3)", np.sqrt(2*lambda_W/np.sqrt(3))),
    ("(1+О»_WВІ)Г—О»_WГ—2", (1+lambda_W**2)*lambda_W*2),
    ("2О»_W+О»_WВі", 2*lambda_W+lambda_W**3),
