#!/usr/bin/env python3
"""
PHASE 2: THE HIGGS POTENTIAL FROM THE О”I LANDSCAPE
=====================================================
The claim: the Mexican Hat potential V(ПҶ) = -ОјВІПҶВІ + О»ПҶвҒҙ is not
fundamental. It is the SHAPE of the information asymmetry О”I
evaluated across the GL(4) fiber directions.

The computation:
1. Parametrise the vacuum perturbation as v = r Г— nМӮ where r is the
   field strength and nМӮ is the direction in sl(4).
2. For each (r, nМӮ), compute the ACS bracket [Form(v), Function(v)]
   and the resulting О”I.
3. Plot О”I(r) for fixed nМӮ. If this is a sombrero, we've derived
   the Higgs mechanism.

The key physics: at r = 0 (no perturbation, exact Minkowski),
the Form and Function are DECOUPLED (no torsion, no curvature).
This is NOT the minimum of О”I вҖ” it's a saddle point.
The minimum is at finite r where the bracket [Form, Function]
balances the direct coupling.
"""

import numpy as np
from numpy.linalg import norm, eigvalsh
from scipy.linalg import expm
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
import os

OUTDIR = "/home/claude/figures"
os.makedirs(OUTDIR, exist_ok=True)

def bracket(A, B):
    return A @ B - B @ A

def chirality_map(T):
    sym_T = (T + T.T) / 2
    anti_T = (T - T.T) / 2
    return 1j * sym_T + anti_T

print("=" * 70)
print("PHASE 2: THE HIGGS POTENTIAL FROM О”I")
print("=" * 70)

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print("""
в”Җв”Җ The Physical Setup в”Җв”Җ

The Palatini vacuum: e = Оҙ (Minkowski vierbein), Пү = 0 (flat connection).
A perturbation of strength r in direction nМӮ:
  e вҶ’ Оҙ + r Г— Form(nМӮ)    [symmetric part of nМӮ]
  Пү вҶ’ r Г— Function(nМӮ)    [antisymmetric part of nМӮ]

The ACS information asymmetry О”I(r, nМӮ) measures the imbalance
between how much Form knows about Function vs vice versa.

At r = 0: no coupling, О”I = 0 (trivially).
At small r: О”I ~ rВІ (from the bracket, Lemma 2.5).
At large r: О”I should decrease (the system thermalises).

The SHAPE of О”I(r) determines whether the vacuum is stable.
""")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# Build the sl(4) basis
print("в”Җв”Җ Building the GL(4) fiber в”Җв”Җ\n")

# Symmetric traceless basis (Form/torsion sector) вҖ” 9 generators
sym_basis = []
sym_names = []
# Diagonal traceless
for name, M in [("hвӮҒ", np.diag([1,-1,0,0])), 
                ("hвӮӮ", np.diag([0,1,-1,0])),
                ("hвӮғ", np.diag([1,1,-1,-1]))]:
    sym_basis.append(M.astype(float))
    sym_names.append(name)
# Off-diagonal symmetric
for i, j, name in [(0,1,"SвӮҖвӮҒ"),(0,2,"SвӮҖвӮӮ"),(0,3,"SвӮҖвӮғ"),
                    (1,2,"SвӮҒвӮӮ"),(1,3,"SвӮҒвӮғ"),(2,3,"SвӮӮвӮғ")]:
    M = np.zeros((4,4)); M[i,j] = M[j,i] = 1
    sym_basis.append(M)
    sym_names.append(name)

# Antisymmetric basis (Function/Lorentz sector) вҖ” 6 generators
anti_basis = []
anti_names = []
for i, j, name in [(0,1,"AвӮҖвӮҒ"),(0,2,"AвӮҖвӮӮ"),(0,3,"AвӮҖвӮғ"),
                    (1,2,"AвӮҒвӮӮ"),(1,3,"AвӮҒвӮғ"),(2,3,"AвӮӮвӮғ")]:
    M = np.zeros((4,4)); M[i,j] = 1; M[j,i] = -1
    anti_basis.append(M)
    anti_names.append(name)

print(f"  Form sector (SymвӮҖ):  {len(sym_basis)} generators")
print(f"  Function sector (o(4)): {len(anti_basis)} generators")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"\nв”Җв”Җ Computing О”I(r) for Fixed Directions в”Җв”Җ\n")

def compute_DI(f_gen, g_gen, epsilon):
    """Compute the ACS information asymmetry proxy at coupling Оө.
    
    О”I(Оө) вүҲ Оө ||f - g|| + 2ОөВІ ||[f,g]|| + ОөВі ||[[f,g],f] + [[f,g],g]||
    
    This is the BCH expansion of the transfer entropy asymmetry.
    The actual О”I involves the SRB measure, but the NORM of the
    BCH terms gives the correct shape.
    """
    f = epsilon * f_gen
    g = epsilon * g_gen
    
    # 1st order: direct asymmetry
    T1 = norm(f - g)
    
    # 2nd order: bracket (curvature)
    L2 = bracket(f_gen, g_gen)
    T2 = 2 * epsilon * norm(L2)
    
    # 3rd order: holonomy
    L3 = bracket(L2, f_gen) + bracket(L2, g_gen)
    T3 = epsilon**2 * norm(L3)
    
    return T1, T2, T3

def DI_potential(f_gen, g_gen, epsilon):
    """The effective potential: V(Оө) = -О”I(Оө).
    
    The system minimises V, which means maximising О”I.
    But О”I has a maximum at finite Оө (the bracket term grows
    then saturates). The potential has a minimum at finite Оө.
    
    More precisely: V(Оө) = ОөВІ ||f-g||ВІ - 2ОөВІ ||[f,g]|| + ОөвҒҙ terms
    
    This IS the Mexican Hat if ||[f,g]|| > ||f-g||.
    """
    L2 = bracket(f_gen, g_gen)
    L3 = bracket(L2, f_gen) + bracket(L2, g_gen)
    
    # The effective potential from the BCH-TE expansion
    # V(r) = rВІ (ОјВІ term) - rВІ Г— bracket (negative massВІ) + rвҒҙ (quartic)
    
    mu_sq = norm(f_gen - g_gen)**2  # "mass" parameter
    bracket_sq = norm(L2)**2         # bracket contribution
    lambda_q = norm(L3)**2           # quartic from holonomy
    
    # V(r) = rВІ (ОјВІ - bracketВІ) + rвҒҙ Г— lambda
    # If bracketВІ > ОјВІ: the origin is UNSTABLE (negative massВІ)
    # The minimum is at r_min = вҲҡ(bracketВІ - ОјВІ) / (2О»)
    
    V = epsilon**2 * (mu_sq - bracket_sq) + epsilon**4 * lambda_q
    
    return V, mu_sq, bracket_sq, lambda_q

# Scan several physical directions
directions = [
    ("Graviton hвӮҠ / Rotation AвӮҒвӮӮ", sym_basis[0], anti_basis[3]),
    ("Graviton hГ— / Boost AвӮҖвӮғ", sym_basis[3], anti_basis[2]),
    ("Torsion SвӮҒвӮғ / Rotation AвӮҒвӮӮ", sym_basis[7], anti_basis[3]),
    ("Cartan hвӮҒ / Boost AвӮҖвӮҒ", sym_basis[0], anti_basis[0]),
    ("Mixed SвӮҖвӮӮ / Rotation AвӮӮвӮғ", sym_basis[5], anti_basis[5]),
]

print(f"  {'Direction':<35} {'ОјВІ':<8} {'[f,g]ВІ':<10} {'О»':<10} {'ОјВІ<[f,g]ВІ?':<12} {'r_min'}")
print(f"  {'-'*85}")

r_values = np.linspace(0, 3, 200)

fig, axes = plt.subplots(2, 3, figsize=(9, 5.5))

for idx, (name, f_gen, g_gen) in enumerate(directions):
    # Compute potential parameters
    _, mu_sq, br_sq, lam = DI_potential(f_gen, g_gen, 1.0)
    
    unstable = br_sq > mu_sq
    if unstable and lam > 1e-10:
        r_min = np.sqrt((br_sq - mu_sq) / (2 * lam))
    else:
        r_min = 0
    
    print(f"  {name:<35} {mu_sq:<8.3f} {br_sq:<10.3f} {lam:<10.3f} {'YES вң“' if unstable else 'no':<12} {r_min:.3f}")
    
    # Plot the potential
    V_vals = [DI_potential(f_gen, g_gen, r)[0] for r in r_values]
    
    ax = axes[idx // 3][idx % 3]
    ax.plot(r_values, V_vals, 'b-', lw=1.5)
    ax.axhline(0, color='gray', lw=0.5, ls='--')
    if r_min > 0:
        V_min = DI_potential(f_gen, g_gen, r_min)[0]
        ax.plot(r_min, V_min, 'ro', markersize=6)
        ax.annotate(f'$r_{{min}}={r_min:.2f}$', (r_min, V_min), 
                   (r_min+0.3, V_min+0.5), fontsize=7, color='red')
    ax.set_title(name.split('/')[0].strip(), fontsize=8, fontweight='bold')
    ax.set_xlabel('$r$ (field strength)', fontsize=7)
    ax.set_ylabel('$V(r)$', fontsize=7)
    ax.grid(True, alpha=0.15)
    ax.tick_params(labelsize=6)

# Use the last subplot for the sombrero cross-section
ax = axes[1][2]

# Find the BEST sombrero direction
best_ratio = 0
best_f, best_g, best_name = None, None, ""

np.random.seed(42)
for trial in range(5000):
    fc = np.random.randn(len(sym_basis))
    fc /= norm(fc)
    f = sum(c*g for c,g in zip(fc, sym_basis))
    
    gc = np.random.randn(len(anti_basis))
    gc /= norm(gc)
    g = sum(c*b for c,b in zip(gc, anti_basis))
    
    L2 = bracket(f, g)
    mu2 = norm(f - g)**2
    br2 = norm(L2)**2
    
    if br2 > mu2 and br2/mu2 > best_ratio:
        best_ratio = br2/mu2
        best_f, best_g = f.copy(), g.copy()
        best_name = f"Random (ratio={br2/mu2:.2f})"

if best_f is not None:
    V_best = [DI_potential(best_f, best_g, r)[0] for r in r_values]
    ax.plot(r_values, V_best, 'r-', lw=2)
    ax.axhline(0, color='gray', lw=0.5, ls='--')
    
    _, mu2, br2, lam = DI_potential(best_f, best_g, 1.0)
    if lam > 1e-10:
        rm = np.sqrt((br2 - mu2) / (2*lam))
        Vm = DI_potential(best_f, best_g, rm)[0]
        ax.plot(rm, Vm, 'ko', markersize=6)
        ax.annotate(f'VEV: $r={rm:.2f}$', (rm, Vm), (rm+0.2, Vm+1), fontsize=7)
    
    ax.set_title('Best Sombrero', fontsize=8, fontweight='bold')
    ax.set_xlabel('$r$', fontsize=7)
    ax.set_ylabel('$V(r)$', fontsize=7)
    ax.grid(True, alpha=0.15)
    ax.tick_params(labelsize=6)

fig.suptitle('$\\Delta\\mathcal{I}$ Potential Landscape: Mexican Hat from Geometry',
            fontsize=11, fontweight='bold', y=1.02)
fig.tight_layout()
fig.savefig(f'{OUTDIR}/fig_higgs_landscape.pdf', dpi=300, bbox_inches='tight')
plt.close()
print(f"\n  Figure saved: fig_higgs_landscape.pdf")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"\nв”Җв”Җ The Sombrero Test в”Җв”Җ\n")

# Count how many random directions give the sombrero shape
n_sombrero = 0
n_total = 10000
ratios = []

for trial in range(n_total):
    fc = np.random.randn(len(sym_basis))
    fc /= norm(fc)
    f = sum(c*g for c,g in zip(fc, sym_basis))
    
    gc = np.random.randn(len(anti_basis))
    gc /= norm(gc)
    g = sum(c*b for c,b in zip(gc, anti_basis))
    
    L2 = bracket(f, g)
    L3 = bracket(L2, f) + bracket(L2, g)
    
    mu2 = norm(f - g)**2
    br2 = norm(L2)**2
    lam = norm(L3)**2
    
    if br2 > mu2 and lam > 1e-10:
        n_sombrero += 1
        ratios.append(br2/mu2)

print(f"  Random directions tested: {n_total}")
print(f"  Sombrero shapes (bracketВІ > ОјВІ): {n_sombrero} ({n_sombrero/n_total*100:.1f}%)")
if ratios:
    print(f"  Ratio [f,g]ВІ/ОјВІ for sombreros: mean={np.mean(ratios):.2f}, max={max(ratios):.2f}")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"\nв”Җв”Җ The 2D Sombrero (Angular Scan) в”Җв”Җ\n")

# For the best sombrero direction, plot V(r, Оё) in 2D
# where Оё is a rotation within the Form sector
if best_f is not None:
    n_r = 100
    n_theta = 100
