#!/usr/bin/env python3
"""
THE KOIDE ANGLE RG FLOW: 11.57В° вҶ’ 12.73В°
===========================================
The bare geometric angle ОёвӮҖ = ПҖ/6 - arctan(1/3) = 11.57В° at the GUT scale.
The observed IR angle is 12.73В°.
Gap: 1.17В°.

This computation runs the Standard Model 1-loop RG equations for the
charged lepton Yukawa couplings from M_GUT down to the IR, and extracts
ОёвӮҖ(Ој) at each scale.

The SM 1-loop beta functions for lepton Yukawas:
  16ПҖВІ dy_i/dt = y_i Г— [ T - (9/4)gвӮӮВІ - (15/4)g'ВІ + (3/2)y_iВІ ]
  
where:
  t = ln(Ој/M_Z)
  T = Tr(3Y_uвҖ Y_u + 3Y_dвҖ Y_d + Y_eвҖ Y_e) вүҲ 3y_tВІ (top dominates)
  gвӮӮ = SU(2) gauge coupling
  g' = U(1) hypercharge coupling

The FLAVOUR-UNIVERSAL terms (T, gвӮӮВІ, g'ВІ) scale ALL Yukawas equally
вҶ’ they DON'T change ОёвӮҖ.

The FLAVOUR-DEPENDENT term (3/2)y_iВІ scales each Yukawa differently
вҶ’ this IS what shifts ОёвӮҖ.

Since y_П„ >> y_Ој >> y_e, the tau Yukawa runs faster than the others,
pulling ОёвӮҖ upward as we flow to the IR.
"""

import numpy as np
from scipy.integrate import solve_ivp
from scipy.optimize import minimize

print("=" * 70)
print("THE KOIDE ANGLE RG FLOW")
print("From GUT Scale (11.57В°) to IR (12.73В°)")
print("=" * 70)

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# Physical constants at M_Z
M_Z = 91.1876  # GeV
v = 246.22      # Higgs VEV, GeV

# Gauge couplings at M_Z (PDG 2024)
alpha1_MZ = 0.01017  # U(1)_Y (GUT normalised: g'ВІ = 5/3 Г— gвӮҒВІ)
alpha2_MZ = 0.03382  # SU(2)_L
alpha3_MZ = 0.1179   # SU(3)_c

g1_MZ = np.sqrt(4 * np.pi * alpha1_MZ)  # ~ 0.357
g2_MZ = np.sqrt(4 * np.pi * alpha2_MZ)  # ~ 0.652
g3_MZ = np.sqrt(4 * np.pi * alpha3_MZ)  # ~ 1.218

# Yukawa couplings at M_Z: y_i = вҲҡ2 m_i / v
m_e = 0.51099895e-3   # GeV
m_mu = 0.1056583755   # GeV
m_tau = 1.77686        # GeV
m_t = 173.1            # GeV (top quark)

y_e_MZ = np.sqrt(2) * m_e / v
y_mu_MZ = np.sqrt(2) * m_mu / v
y_tau_MZ = np.sqrt(2) * m_tau / v
y_t_MZ = np.sqrt(2) * m_t / v

print(f"\nв”Җв”Җ Initial Conditions at M_Z = {M_Z} GeV в”Җв”Җ\n")
print(f"  Gauge couplings: gвӮҒ={g1_MZ:.4f}, gвӮӮ={g2_MZ:.4f}, gвӮғ={g3_MZ:.4f}")
print(f"  Yukawa couplings:")
print(f"    y_e  = {y_e_MZ:.6e}")
print(f"    y_Ој  = {y_mu_MZ:.6e}")
print(f"    y_П„  = {y_tau_MZ:.6e}")
print(f"    y_t  = {y_t_MZ:.4f}")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# Extract ОёвӮҖ from Yukawa couplings
def extract_theta0(y_e, y_mu, y_tau):
    """Extract the Koide angle ОёвӮҖ from three Yukawa couplings.
    Koide parametrisation: вҲҡm_i = A(1 + вҲҡ2 cos(ОёвӮҖ + 2ПҖi/3))
    Since y_i = вҲҡ2 m_i / v, we have вҲҡy_i вҲқ m_i^{1/4} Г— const
    Actually: вҲҡm_i = вҲҡ(y_i v/вҲҡ2), so we fit to вҲҡ(y_i).
    """
    # masses from yukawas
    masses = [(y * v / np.sqrt(2)) for y in [y_e, y_mu, y_tau]]
    sqrt_m = sorted([np.sqrt(m) for m in masses])
    
    def err(params):
        A, th0 = params
        pred = sorted([A * (1 + np.sqrt(2) * np.cos(th0 + 2*np.pi*k/3)) 
                       for k in range(3)])
        if any(p <= 0 for p in pred):
            return 1e10
        return sum((np.log(p/o))**2 for p, o in zip(pred, sqrt_m))
    
    res = minimize(err, [sum(sqrt_m)/3, 0.2], method='Nelder-Mead',
                  options={'xatol': 1e-14, 'fatol': 1e-16, 'maxiter': 50000})
    return np.degrees(res.x[1])

theta0_MZ = extract_theta0(y_e_MZ, y_mu_MZ, y_tau_MZ)
print(f"\n  ОёвӮҖ at M_Z: {theta0_MZ:.4f}В°")
print(f"  Target:    12.73В°")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# 1-loop RG equations
print(f"\nв”Җв”Җ SM 1-Loop Beta Functions в”Җв”Җ\n")

def rge_system(t, y_vec):
    """
    SM 1-loop RG equations.
    y_vec = [g1, g2, g3, y_e, y_mu, y_tau, y_t]
    t = ln(Ој/M_Z)
    
    16ПҖВІ dg_i/dt = b_i g_iВі
    16ПҖВІ dy_l/dt = y_l Г— [T - cвӮҒg'ВІ - cвӮӮgвӮӮВІ + (3/2)y_lВІ]
    16ПҖВІ dy_t/dt = y_t Г— [T - cвӮҒ'g'ВІ - cвӮӮ'gвӮӮВІ - 8gвӮғВІ + (9/2)y_tВІ]
    """
    g1, g2, g3, ye, ymu, ytau, yt = y_vec
    
    # Beta function coefficients (SM with 3 generations)
    b1 = 41/10   # U(1)
    b2 = -19/6   # SU(2) 
    b3 = -7      # SU(3)
    
    # Trace term: T = 3y_tВІ + 3y_bВІ + y_П„ВІ вүҲ 3y_tВІ + y_П„ВІ
    # (neglecting light quark and lepton Yukawas)
    T = 3 * yt**2 + ytau**2
    
    # Lepton gauge coefficients
    # For charged leptons: 16ПҖВІ dy_l/dt = y_l(T - (9/4)gвӮӮВІ - (15/4)g'ВІ + (3/2)y_lВІ)
    # Using GUT-normalised gвӮҒ: g' = вҲҡ(3/5) gвӮҒ
    gp_sq = (3/5) * g1**2
    
    c_lepton_gp = 15/4    # coefficient of g'ВІ for leptons
    c_lepton_g2 = 9/4     # coefficient of gвӮӮВІ
    
    # Top quark gauge coefficients
    c_top_gp = 17/20      # coefficient of g'ВІ for up-type quarks  
    c_top_g2 = 9/4
    c_top_g3 = 8
    
    factor = 1 / (16 * np.pi**2)
    
    # Gauge coupling running
    dg1 = factor * b1 * g1**3
    dg2 = factor * b2 * g2**3
    dg3 = factor * b3 * g3**3
    
    # Lepton Yukawa running
    common_lepton = T - c_lepton_g2 * g2**2 - c_lepton_gp * gp_sq
    
    dye = factor * ye * (common_lepton + 1.5 * ye**2)
    dymu = factor * ymu * (common_lepton + 1.5 * ymu**2)
    dytau = factor * ytau * (common_lepton + 1.5 * ytau**2)
    
    # Top Yukawa running
    dyt = factor * yt * (T - c_top_gp * gp_sq - c_top_g2 * g2**2 
                         - c_top_g3 * g3**2 + 4.5 * yt**2)
    
    return [dg1, dg2, dg3, dye, dymu, dytau, dyt]

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# Run from M_Z UP to M_GUT
print(f"  Running from M_Z = {M_Z:.1f} GeV up to M_GUT = 2Г—10В№вҒ¶ GeV...\n")

t_MZ = 0  # ln(M_Z/M_Z) = 0
t_GUT = np.log(2e16 / M_Z)  # ln(M_GUT/M_Z) вүҲ 39.3

y0 = [g1_MZ, g2_MZ, g3_MZ, y_e_MZ, y_mu_MZ, y_tau_MZ, y_t_MZ]

# Solve ODE from t=0 (M_Z) to t=t_GUT
sol = solve_ivp(rge_system, [t_MZ, t_GUT], y0, 
                method='RK45', max_step=0.1, rtol=1e-10, atol=1e-13,
                dense_output=True)

if not sol.success:
    print(f"  ODE solver failed: {sol.message}")
else:
    print(f"  ODE solved successfully ({len(sol.t)} steps)")

# Extract ОёвӮҖ at various scales
scales_t = np.linspace(t_MZ, t_GUT, 100)
scales_GeV = M_Z * np.exp(scales_t)
theta0_running = []

print(f"\n  {'Scale (GeV)':<16} {'y_e':<12} {'y_Ој':<12} {'y_П„':<12} {'y_t':<8} {'ОёвӮҖ (deg)'}")
print(f"  {'-'*72}")

for i, t in enumerate(scales_t):
    state = sol.sol(t)
    g1, g2, g3, ye, ymu, ytau, yt = state
    
    if ye > 0 and ymu > 0 and ytau > 0:
        th0 = extract_theta0(ye, ymu, ytau)
        theta0_running.append(th0)
    else:
        theta0_running.append(np.nan)
    
    if i % 20 == 0 or i == len(scales_t) - 1:
        mu = M_Z * np.exp(t)
        if mu > 1e12:
            mu_str = f"{mu:.1e}"
        else:
            mu_str = f"{mu:.1f}"
        print(f"  {mu_str:<16} {ye:<12.4e} {ymu:<12.4e} {ytau:<12.4e} {yt:<8.4f} {theta0_running[-1]:.4f}")

theta0_running = np.array(theta0_running)

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"\nв”Җв”Җ Results в”Җв”Җ\n")

theta0_IR = theta0_running[0]   # at M_Z
theta0_UV = theta0_running[-1]  # at M_GUT

# The bare geometric prediction
theta0_bare = np.degrees(np.pi/6 - np.arctan(1/3))  # 11.565В°

print(f"  ОёвӮҖ at M_Z (IR):          {theta0_IR:.4f}В°")
print(f"  ОёвӮҖ at M_GUT (UV):        {theta0_UV:.4f}В°")
print(f"  Shift (UV вҶ’ IR):         {theta0_IR - theta0_UV:+.4f}В°")
print(f"")
print(f"  Bare geometric angle:     {theta0_bare:.4f}В°")
print(f"  Observed IR angle:        12.7328В°")
print(f"  Required shift:           {12.7328 - theta0_bare:+.4f}В°")
print(f"  RG-computed shift:        {theta0_IR - theta0_UV:+.4f}В°")

# The KEY question: does the RG shift go in the RIGHT DIRECTION?
shift_rg = theta0_IR - theta0_UV
shift_needed = 12.7328 - theta0_bare

print(f"\n  Direction match: {'YES вң“' if np.sign(shift_rg) == np.sign(shift_needed) else 'NO вң—'}")
print(f"  Magnitude: RG gives {abs(shift_rg):.4f}В° of the needed {abs(shift_needed):.4f}В°")
print(f"  Fraction explained: {abs(shift_rg / shift_needed) * 100:.1f}%")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"\nв”Җв”Җ The Flavour-Dependent Shift в”Җв”Җ\n")

# The shift comes entirely from the (3/2)y_iВІ term.
# At 1-loop, the flavour-dependent part shifts ОёвӮҖ by:
#   О”ОёвӮҖ вүҲ (3/(32ПҖВІ)) Г— (y_П„ВІ - y_ОјВІ) Г— ln(M_GUT/M_Z)
# (since y_eВІ вүҲ 0 and y_ОјВІ вүҲ 0 compared to y_П„ВІ)

delta_theta_analytic = (3 / (32 * np.pi**2)) * (y_tau_MZ**2) * t_GUT
delta_theta_analytic_deg = np.degrees(delta_theta_analytic)

print(f"  Analytic estimate of flavour-dependent shift:")
print(f"    О”ОёвӮҖ вүҲ (3/(32ПҖВІ)) Г— y_П„ВІ Г— ln(M_GUT/M_Z)")
print(f"         = (3/(32ПҖВІ)) Г— {y_tau_MZ**2:.4e} Г— {t_GUT:.2f}")
print(f"         = {delta_theta_analytic:.6f} rad = {delta_theta_analytic_deg:.4f}В°")
print(f"")
print(f"  This is the dominant contribution. The exact numerical RG gives")
print(f"  {abs(shift_rg):.4f}В° (including gauge coupling effects).")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# Now the critical test: start from the BARE angle at M_GUT and run DOWN
print(f"\nв”Җв”Җ Critical Test: Start from Bare Angle at GUT Scale в”Җв”Җ\n")

# At the GUT scale, the RG gives ОёвӮҖ(M_GUT) from the SM Yukawas
# But the ACS PREDICTS ОёвӮҖ_bare = 11.57В° at the GUT scale.
# We need to check: if we SET ОёвӮҖ = 11.57В° at M_GUT, what ОёвӮҖ do we get at M_Z?

# Get the GUT-scale Yukawa values from the RG run
state_GUT = sol.sol(t_GUT)
_, _, _, ye_GUT, ymu_GUT, ytau_GUT, _ = state_GUT

print(f"  SM Yukawas at M_GUT (from running UP):")
print(f"    y_e  = {ye_GUT:.6e}")
print(f"    y_Ој  = {ymu_GUT:.6e}")
print(f"    y_П„  = {ytau_GUT:.6e}")
print(f"    ОёвӮҖ(M_GUT) from SM = {theta0_UV:.4f}В°")

# Now: construct Yukawas at M_GUT that give ОёвӮҖ = 11.57В°
# while keeping the OVERALL scale and Koide ratio Q = 2/3

# The Koide parametrisation at GUT scale with ОёвӮҖ_bare:
theta0_bare_rad = np.radians(theta0_bare)

# We need to find A such that the TOTAL Yukawa normalization matches
# the SM value at the GUT scale
# Sum of вҲҡmasses: S = вҲҡ(y_e v/вҲҡ2) + вҲҡ(y_mu v/вҲҡ2) + вҲҡ(y_tau v/вҲҡ2)
masses_GUT = [(y * v / np.sqrt(2)) for y in [ye_GUT, ymu_GUT, ytau_GUT]]
sqrt_m_GUT = sorted([np.sqrt(m) for m in masses_GUT])
S_GUT = sum(sqrt_m_GUT)
A_GUT = S_GUT / 3  # From Koide: S = 3A

# Reconstruct masses with bare ОёвӮҖ
sqrt_m_bare = sorted([A_GUT * (1 + np.sqrt(2) * np.cos(theta0_bare_rad + 2*np.pi*k/3)) 
                      for k in range(3)])

if any(s <= 0 for s in sqrt_m_bare):
    print(f"  WARNING: negative вҲҡm at bare angle вҖ” adjusting A")
    # Need larger A
    for A_try in np.linspace(A_GUT * 0.5, A_GUT * 2.0, 100):
        sqrt_m_try = sorted([A_try * (1 + np.sqrt(2) * np.cos(theta0_bare_rad + 2*np.pi*k/3)) 
                            for k in range(3)])
        if all(s > 0 for s in sqrt_m_try):
            A_GUT = A_try
            sqrt_m_bare = sqrt_m_try
            break

masses_bare = [s**2 for s in sqrt_m_bare]
yukawas_bare = [np.sqrt(2) * m / v for m in masses_bare]

print(f"\n  Bare Koide masses at M_GUT (ОёвӮҖ = {theta0_bare:.2f}В°):")
for name, m in zip(["e", "Ој", "П„"], masses_bare):
    print(f"    m_{name} = {m:.6e} GeV")

# Check: extract ОёвӮҖ back
theta0_check = extract_theta0(*yukawas_bare)
print(f"  ОёвӮҖ extracted: {theta0_check:.4f}В° (should be {theta0_bare:.4f}В°)")

# Now run these DOWN from M_GUT to M_Z
print(f"\n  Running bare Yukawas DOWN from M_GUT to M_Z...")

# Need gauge couplings at GUT scale too
g1_GUT, g2_GUT, g3_GUT = state_GUT[0], state_GUT[1], state_GUT[2]
yt_GUT = state_GUT[6]

y0_bare = [g1_GUT, g2_GUT, g3_GUT, yukawas_bare[0], yukawas_bare[1], yukawas_bare[2], yt_GUT]

# Run DOWN: from t_GUT to t_MZ (reverse direction)
sol_down = solve_ivp(rge_system, [t_GUT, t_MZ], y0_bare,
                     method='RK45', max_step=0.1, rtol=1e-10, atol=1e-13,
                     dense_output=True)

if sol_down.success:
    state_IR = sol_down.sol(t_MZ)
    ye_IR, ymu_IR, ytau_IR = state_IR[3], state_IR[4], state_IR[5]
    
    theta0_IR_from_bare = extract_theta0(ye_IR, ymu_IR, ytau_IR)
    
    masses_IR = [(y * v / np.sqrt(2)) for y in [ye_IR, ymu_IR, ytau_IR]]
    
    print(f"\n  Masses at M_Z (from bare ОёвӮҖ = {theta0_bare:.2f}В° at GUT):")
    for name, m in zip(["e", "Ој", "П„"], masses_IR):
        print(f"    m_{name} = {m*1e3:.4f} MeV")
    
    print(f"\n  ОёвӮҖ at M_Z (from bare): {theta0_IR_from_bare:.4f}В°")
    print(f"  ОёвӮҖ observed:            12.7328В°")
    print(f"  RG shift:               {theta0_IR_from_bare - theta0_bare:+.4f}В°")
    print(f"  Needed shift:           {12.7328 - theta0_bare:+.4f}В°")
    
    match_pct = abs((theta0_IR_from_bare - theta0_bare) / (12.7328 - theta0_bare)) * 100
    
    print(f"\n  {'='*50}")
    print(f"  RG FLOW ACCOUNTS FOR {match_pct:.1f}% OF THE GAP")
    print(f"  {'='*50}")
else:
    print(f"  Downward RG failed: {sol_down.message}")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# Generate figure
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
import os

fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(9, 4))

# Panel 1: ОёвӮҖ running
valid = ~np.isnan(theta0_running)
ax1.plot(np.log10(scales_GeV[valid]), theta0_running[valid], 'b-', lw=2)
ax1.axhline(12.7328, color='red', ls='--', lw=1, label='Observed IR (12.73В°)')
ax1.axhline(theta0_bare, color='green', ls='--', lw=1, label=f'Bare geometric ({theta0_bare:.2f}В°)')
ax1.set_xlabel('logвӮҒвӮҖ(Ој / GeV)', fontsize=10)
ax1.set_ylabel('ОёвӮҖ (degrees)', fontsize=10)
ax1.set_title('Koide Angle RG Flow', fontsize=11, fontweight='bold')
ax1.legend(fontsize=8)
ax1.grid(True, alpha=0.2)

# Panel 2: Yukawa running (ratios)
ye_run = []
ymu_run = []
ytau_run = []
for t in scales_t:
    state = sol.sol(t)
    ye_run.append(state[3])
    ymu_run.append(state[4])
    ytau_run.append(state[5])

ye_run = np.array(ye_run)
ymu_run = np.array(ymu_run)
ytau_run = np.array(ytau_run)

# Plot ratios normalised to M_Z values
ax2.plot(np.log10(scales_GeV), ytau_run/ytau_run[0], 'r-', lw=1.5, label='y_П„ / y_П„(M_Z)')
ax2.plot(np.log10(scales_GeV), ymu_run/ymu_run[0], 'b-', lw=1.5, label='y_Ој / y_Ој(M_Z)')
ax2.plot(np.log10(scales_GeV), ye_run/ye_run[0], 'g-', lw=1.5, label='y_e / y_e(M_Z)')
ax2.set_xlabel('logвӮҒвӮҖ(Ој / GeV)', fontsize=10)
ax2.set_ylabel('y_i(Ој) / y_i(M_Z)', fontsize=10)
ax2.set_title('Yukawa Coupling Running', fontsize=11, fontweight='bold')
ax2.legend(fontsize=8)
ax2.grid(True, alpha=0.2)

fig.tight_layout()
os.makedirs('/home/claude/figures', exist_ok=True)
fig.savefig('/home/claude/figures/fig_koide_rg_flow.pdf', dpi=300, bbox_inches='tight')
plt.close()
print(f"\n  Figure saved: fig_koide_rg_flow.pdf")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"\n{'='*70}")
print("FINAL RESULT")
print(f"{'='*70}")
print(f"""
  BARE GEOMETRIC ANGLE (ACS prediction at Palatini scale):
    ОёвӮҖ_bare = ПҖ/6 - arctan(1/3) = {theta0_bare:.4f}В°
    
  OBSERVED IR ANGLE (from charged lepton masses):
    ОёвӮҖ_obs = 12.7328В°
    
  GAP: {12.7328 - theta0_bare:.4f}В°
    
  1-LOOP RG FLOW:
    The SM beta functions for lepton Yukawa couplings shift ОёвӮҖ
    as the energy scale runs from M_GUT to M_Z.
    
    The dominant contribution is the tau Yukawa self-energy:
    О”ОёвӮҖ вүҲ (3/(32ПҖВІ)) Г— y_П„ВІ Г— ln(M_GUT/M_Z)
    
    The tau Yukawa y_П„ = {y_tau_MZ:.4e} is 200Г— larger than y_Ој,
    so it pulls the mass triangle TOWARD the П„ vertex, increasing ОёвӮҖ.
    
    Computed shift: {abs(theta0_IR - theta0_UV):.4f}В°
    (from SM Yukawas running up)
    
  STATUS:
    Direction of shift: {'CORRECT вң“' if np.sign(shift_rg) == np.sign(shift_needed) else 'WRONG вң—'}
    Fraction of gap explained by 1-loop RG: {abs(shift_rg/shift_needed)*100:.1f}%
""")



