# The three masses sit on a circle of radius вҲҡ2 A in the weight plane
# The angle ОёвӮҖ measures the rotation of this triangle

# With the B-L VEV projection, the effective coupling at each order is:
# Order 1 (П„): yвӮҒ ~ Оө (full coupling, no color suppression)
# Order 2 (Ој): yвӮӮ ~ ОөВІ (one bracket)
# Order 3 (e): yвӮғ ~ ОөВі (two brackets)
# The NEUTRINO adds 1/3 Г— Оө on top of order 3

# The Koide angle is determined by:
# tan(3ОёвӮҖ) = (yвӮғ - yвӮҒ) Г— вҲҡ3 / (2yвӮӮ - yвӮҒ - yвӮғ)
# For y_i ~ Оө^i with Оө small:
# tan(3ОёвӮҖ) вүҲ (ОөВі - Оө) Г— вҲҡ3 / (2ОөВІ - Оө - ОөВі) вүҲ -вҲҡ3 (for Оө вүӘ 1)
# This gives 3ОёвӮҖ вүҲ -60В° + nГ—120В°, i.e., ОёвӮҖ вүҲ 20В° or ОёвӮҖ вүҲ -20В°

# But the physical ОёвӮҖ = 12.73В° вҖ” let me compute with actual masses

# From the Koide fit: ОёвӮҖ is determined by the mass ratios
# вҲҡm_П„ / вҲҡm_e = (1 + вҲҡ2 cos ОёвӮҖ) / (1 + вҲҡ2 cos(ОёвӮҖ + 4ПҖ/3))

from scipy.optimize import brentq

def koide_angle_eq(theta0):
    """Equation for ОёвӮҖ from the mass ratios."""
    sqrt_masses = [np.sqrt(m_e), np.sqrt(105.6583755), np.sqrt(m_tau)]
    A = sum(sqrt_masses) / 3
    predicted = [A * (1 + np.sqrt(2)*np.cos(theta0 + 2*np.pi*i/3)) for i in range(3)]
    predicted.sort()
    # Match the ratio of largest to smallest
    return predicted[2]/predicted[0] - sqrt_masses[2]/sqrt_masses[0]

# Scan for the right ОёвӮҖ
theta0_phys = None
for t0_init in np.linspace(0.01, 1.0, 50):
    try:
        t0 = brentq(koide_angle_eq, t0_init - 0.02, t0_init + 0.02)
        if 0.1 < t0 < 0.5:
            theta0_phys = t0
            break
    except:
        pass

if theta0_phys:
    print(f"  Physical Koide angle: ОёвӮҖ = {np.degrees(theta0_phys):.4f}В°")
