#
# For the up-type mass matrix:
#   M_u(3,2) ~ Оө^1 (orders 1+2-2 = 1)
#   M_u(3,1) ~ Оө^2 (orders 1+3-2 = 2)
#   M_u(2,1) ~ Оө^3 (orders 2+3-2 = 3)
#
