#!/usr/bin/env python3
"""
PHASE 5: CKM FROM BI-DOUBLET MISALIGNMENT
===========================================
The Phase 4 negative result showed: if both up and down mass matrices
have the SAME texture, V_CKM = identity.

The fix: in Pati-Salam, the bi-doublet ОҰ = (1,2,2) has TWO independent 
Yukawa couplings h and hМғ, corresponding to ОҰ and ОҰМғ = П„вӮӮОҰ*П„вӮӮ.

  M_u = h ОәвӮҒ + hМғ ОәвӮӮ    (up-type mass matrix)
  M_d = h ОәвӮӮ + hМғ ОәвӮҒ    (down-type mass matrix)

The KEY: in the ACS bracket structure,
  h  comes from the SYMMETRIC part of [T_{B-L}, g] вҶ’ SYMMETRIC in gen space
  hМғ comes from the ANTISYMMETRIC part                вҶ’ ANTISYMMETRIC in gen space

Because h is symmetric and hМғ is antisymmetric, M_u and M_d are 
DIFFERENT non-symmetric matrices. Their SVD diagonalisations differ,
generating CKM mixing.
"""

import numpy as np
from numpy.linalg import norm, svd, det
from scipy.optimize import minimize

def bracket(A, B):
    return A @ B - B @ A

print("=" * 70)
print("PHASE 5: CKM FROM BI-DOUBLET MISALIGNMENT")
print("=" * 70)

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# Physical constants
v = 246.22  # Higgs VEV, GeV
eps = 0.22650  # Wolfenstein parameter = BCH coupling

# tan(ОІ) from bracket norms (proved in Phase 4)
tan_beta = 0.5
sin_beta = tan_beta / np.sqrt(1 + tan_beta**2)  # = 1/вҲҡ5
cos_beta = 1 / np.sqrt(1 + tan_beta**2)         # = 2/вҲҡ5

kappa1 = v * sin_beta  # up-type VEV
kappa2 = v * cos_beta  # down-type VEV

print(f"\n  tan(ОІ) = {tan_beta} (from bracket norms)")
print(f"  ОәвӮҒ = v sin ОІ = {kappa1:.2f} GeV (up-type)")
print(f"  ОәвӮӮ = v cos ОІ = {kappa2:.2f} GeV (down-type)")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# Step 1: Build h (symmetric) and hМғ (antisymmetric) in generation space
# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"\nв”Җв”Җ Step 1: Yukawa Matrices h and hМғ в”Җв”Җ\n")

# The symmetric Yukawa h comes from the torsion bracket [T_{B-L}, g].
# Its generation-space structure is HIERARCHICAL:
#   h_{33} ~ 1 (heaviest generation, 1st BCH order)
#   h_{22} ~ ОөВІ (2nd generation, 2nd BCH order) 
#   h_{11} ~ ОөвҒҙ (lightest, 3rd BCH order)
#   h_{ij} ~ Оө^{|i-j|} Г— geometric mean (off-diagonal, cross-brackets)
#
# The normalisation is set by m_t = h_{33} Г— ОәвӮҒ for the top quark.

# Physical quark masses at 2 GeV (MeV) for normalisation
m_t = 172500  # MeV
m_c = 1270
m_u_phys = 2.16
m_b = 4180
m_s = 93.4
m_d_phys = 4.67

# h is symmetric, entries ~ вҲҡ(m_i m_j) / v_u (Fritzsch-like)
# But we use the BCH suppression: h_{ij} = hвӮҖ Г— Оө^{(3-i)+(3-j)} / ((3-i)!(3-j)!)
# Simplified: the EIGENVALUES of h are the up-type Yukawas y_u, y_c, y_t
# and the EIGENVECTORS are close to the identity (nearly diagonal).

# For the symmetric Yukawa, the BEST texture is nearest-neighbour:
# h = [[0, A_12, 0], [A_12, 0, A_23], [0, A_23, h_33]]
# with A_12 = вҲҡ(m_1 m_2)/ОәвӮҒ, A_23 = вҲҡ(m_2 m_3)/ОәвӮҒ, h_33 = m_3/ОәвӮҒ

# But we DON'T know which masses to use for h (the Yukawa coupling),
# since the PHYSICAL masses involve both h and hМғ.
# Instead, use the bracket norms to set the RELATIVE entries.

# The bracket structure gives:
# hвӮғвӮғ : hвӮӮвӮӮ : hвӮҒвӮҒ = 1 : ОөВІ : ОөвҒҙ
# hвӮӮвӮғ = hвӮғвӮӮ : hвӮҒвӮӮ = hвӮӮвӮҒ = вҲҡ(hвӮӮвӮӮ hвӮғвӮғ) : вҲҡ(hвӮҒвӮҒ hвӮӮвӮӮ)
#            = Оө : ОөВі
# hвӮҒвӮғ = 0 (non-adjacent BCH orders, nearest-neighbour only)

h33 = 1.0
h22 = eps**2
h11 = eps**4
h23 = np.sqrt(h22 * h33)  # = Оө
h12 = np.sqrt(h11 * h22)  # = ОөВі
h13 = 0  # nearest-neighbour

h = np.array([
    [h11,  h12,  h13],
    [h12,  h22,  h23],
    [h13,  h23,  h33]
])

# The antisymmetric Yukawa hМғ comes from the gauge bracket [[f,g],f].
# It is ANTISYMMETRIC in generation space (zero diagonal).
# Its norm relative to h is set by the bracket ratio:
# ||L3_anti|| / ||L3_sym|| = ||[[f,g],f]|| / ||[[f,g],g]||

T_BL = np.diag([1/3, 1/3, 1/3, -1]).astype(float)
A03 = np.zeros((4,4)); A03[0,3]=1; A03[3,0]=-1
A13_g = np.zeros((4,4)); A13_g[1,3]=1; A13_g[3,1]=-1
A23_g = np.zeros((4,4)); A23_g[2,3]=1; A23_g[3,2]=-1
g_CL = (A03 + A13_g + A23_g) / np.sqrt(3)

L2 = bracket(T_BL, g_CL)
L3_anti = bracket(L2, T_BL)
L3_sym = bracket(L2, g_CL)

r_anti_sym = norm(L3_anti) / norm(L3_sym)
print(f"  ||L3_anti||/||L3_sym|| = {r_anti_sym:.6f}")
print(f"  This ratio scales the antisymmetric Yukawa relative to h.")

# hМғ entries: antisymmetric, with the same BCH order suppression
# hМғ_{23} = -hМғ_{32} = r Г— Оө (same order as h_{23})
# hМғ_{12} = -hМғ_{21} = r Г— ОөВі
# hМғ_{13} = -hМғ_{31} = r Г— ОөВІ (this one is NOT zero! 
#   The antisymmetric coupling between non-adjacent orders exists
#   because the GAUGE bracket has different selection rules.)

ht23 = r_anti_sym * eps      # scaled by bracket ratio
ht12 = r_anti_sym * eps**3
ht13 = r_anti_sym * eps**2   # non-zero for antisymmetric!

h_tilde = np.array([
    [0,      ht12,   ht13],
    [-ht12,  0,      ht23],
    [-ht13,  -ht23,  0]
])

print(f"\n  Symmetric Yukawa h:")
for row in h:
    print(f"    [{row[0]:10.6f} {row[1]:10.6f} {row[2]:10.6f}]")

print(f"\n  Antisymmetric Yukawa hМғ:")
for row in h_tilde:
    print(f"    [{row[0]:10.6f} {row[1]:10.6f} {row[2]:10.6f}]")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# Step 2: Mass matrices M_u = h ОәвӮҒ + hМғ ОәвӮӮ, M_d = h ОәвӮӮ + hМғ ОәвӮҒ
# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"\nв”Җв”Җ Step 2: Mass Matrices в”Җв”Җ\n")

# Include the CP phase Оұ in the down-type VEV
# вҹЁОҰвҹ© = diag(ОәвӮҒ, ОәвӮӮ e^{iОұ})
# For now, scan Оұ to find best fit

def compute_ckm_bidoublet(alpha_phase):
    """Compute CKM for given CP phase Оұ in the bi-doublet VEV."""
    k1 = kappa1
    k2 = kappa2 * np.exp(1j * alpha_phase)
    
    M_u = h * k1 + h_tilde * k2
    M_d = h * k2 + h_tilde * k1
    
    # Normalise: scale so that largest singular value of M_u = m_t
    U_u, s_u, Vh_u = svd(M_u)
    scale_u = m_t / (s_u[-1] * 1000)  # convert to GeV in output
    M_u_scaled = M_u * (m_t / s_u[-1])
    
    U_d, s_d, Vh_d = svd(M_d)
    # Scale M_d so that largest singular value = m_b
    M_d_scaled = M_d * (m_b / s_d[-1])
    
    # Re-SVD the scaled matrices
    U_u, s_u, Vh_u = svd(M_u_scaled)
    U_d, s_d, Vh_d = svd(M_d_scaled)
    
    # CKM = V_uLвҖ  V_dL (left-handed rotations from SVD)
    V_ckm = U_u.conj().T @ U_d
    
    return V_ckm, sorted(s_u), sorted(s_d)

# Scan Оұ
