g2 = Rational(4, 3)
g2_sq = g2**2  # = 16/9
g4_val = g2**4  # = 256/81

# Simplified 1-loop QFP equations (dominant terms):
# 24О»вӮҒВІ вүҲ 6gвҒҙ вҶ’ О»вӮҒ вүҲ gВІ/2вҲҡ6 ... no, let me be more careful.
