        L4_val = float(sol[L4_s])
        # Compute О»_eff at tan ОІ = large (say tan ОІ вҶ’ вҲһ, cos 2ОІ вҶ’ -1):
        lam_eff_large_tb = L1_val + L2_val  # dominant for large tan ОІ
