        print(f"    О»вӮғ = {L3_val:.6f}")
        print(f"    О»вӮ„ = {L4_val:.6f}")
        print(f"    О»_eff (tan ОІ вҶ’ вҲһ) вүҲ О»вӮҒ + О»вӮӮ = {lam_eff_large_tb:.6f}")
        print(f"    О»_eff (tan ОІ вҶ’ 0) вүҲ О»вӮҒ - О»вӮӮ = {lam_eff_small_tb:.6f}")
        print(f"    Bracket value: О» = 2вҲҡ3/27 = {bracket_lambda:.6f}")

