#!/usr/bin/env python3
"""
RICCI TENSOR AND FLOW IN THE ACS FRAMEWORK
=============================================
The curvature R^{ab} = dПү + ПүвҲ§Пү is the 2nd-order ACS bracket.
The Ricci tensor R_{ОјОҪ} is its contraction.
Ricci flow вҲӮ_t g = -2 Ric is the ACS evolving toward О”I = 0.

This computation:
1. Builds the Ricci tensor from Palatini variables (e, Пү)
2. Computes Ricci flow on discrete lattices
3. Shows convergence to constant curvature = ACS attractor
4. Connects Ricci scalar to О”I via the BCH-TE morphism
5. Demonstrates on SВІ, HВІ, flat torus
"""

import numpy as np
from numpy.linalg import norm, det, inv, eigvalsh
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
from scipy.linalg import expm
import os

OUTDIR = "/home/claude/figures"
os.makedirs(OUTDIR, exist_ok=True)

np.set_printoptions(precision=4, suppress=True)

print("=" * 70)
print("RICCI TENSOR AND FLOW IN THE ACS FRAMEWORK")
print("=" * 70)

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print("""
в”Җв”Җ The ACS Structure of Ricci Flow в”Җв”Җ

In the Palatini formulation:
  Form  = vierbein e^a_Ој  (encodes the metric: g_ОјОҪ = О·_ab e^a_Ој e^b_ОҪ)
  Function = connection Пү^{ab}_Ој (encodes parallel transport)

The ACS coupling orders:
  1st order: Torsion T^a = de^a + Пү^a_b вҲ§ e^b
  2nd order: Curvature R^{ab} = dПү^{ab} + Пү^a_c вҲ§ Пү^{cb}  (= [Пү,Пү])
  3rd order: Bianchi D_{[Ој}F_{ОҪПҒ]} = 0

The RICCI TENSOR is the contraction of the 2nd-order bracket:
  R_ОјОҪ = e^a_Ој e^b_ОҪ R_{ab}  (vierbein contracts Lorentz вҶ’ spacetime)

RICCI FLOW is Hamilton's equation:
  вҲӮg_ОјОҪ/вҲӮt = -2 R_ОјОҪ

In ACS language:
  The metric evolves to MINIMIZE the curvature bracket.
  R_ОјОҪ = 0 (Ricci flat) is the attractor.
  Ricci flow = the system evolving toward О”I = 0.

Key insight: R is built from [Пү,Пү] (the Function self-bracket).
When R_ОјОҪ вҶ’ 0, the bracket vanishes вҶ’ the system is Abelian вҶ’ О”I = 0.
When R_ОјОҪ вү  0, the bracket is active вҶ’ asymmetry drives evolution.
""")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print("в”Җв”Җ Part 1: Discrete Ricci Curvature on Graphs в”Җв”Җ\n")

# Use Ollivier-Ricci curvature on graphs as a discrete model
# This is the closest analog to continuous Ricci curvature
# for discrete/lattice ACS

def ollivier_ricci(adj_matrix, x, y, alpha=0.5):
    """Compute Ollivier-Ricci curvature between adjacent nodes x, y.
    Uses the lazy random walk measure: m_x = Оұ Оҙ_x + (1-Оұ)/deg(x) ОЈ_{y~x} Оҙ_y
    
    The Ollivier-Ricci curvature is:
      Оә(x,y) = 1 - WвӮҒ(m_x, m_y) / d(x,y)
    where WвӮҒ is the Wasserstein-1 distance.
    
    For adjacent nodes with d(x,y)=1, this simplifies.
    """
    n = len(adj_matrix)
    deg_x = np.sum(adj_matrix[x])
    deg_y = np.sum(adj_matrix[y])
    
    if deg_x == 0 or deg_y == 0:
        return 0.0
    
    # Lazy random walk distributions
    m_x = np.zeros(n)
    m_x[x] = alpha
    for j in range(n):
        if adj_matrix[x][j] > 0:
            m_x[j] += (1 - alpha) / deg_x
    
    m_y = np.zeros(n)
    m_y[y] = alpha
    for j in range(n):
        if adj_matrix[y][j] > 0:
            m_y[j] += (1 - alpha) / deg_y
    
    # Wasserstein distance (Earth mover's distance)
    # For graphs, WвӮҒ = ОЈ |m_x(z) - m_y(z)| Г— d(z, midpoint) approximately
    # Simplified: count overlap
    overlap = np.sum(np.minimum(m_x, m_y))
    kappa = overlap  # Simplified curvature proxy
    
    # More precise: use the number of common neighbours
    common = sum(1 for j in range(n) if adj_matrix[x][j] > 0 and adj_matrix[y][j] > 0)
    
    # Ollivier's formula for regular graphs:
    # Оә(x,y) вүҲ (common neighbours) / max(deg_x, deg_y) + correction
    kappa_precise = common / max(deg_x, deg_y) - (1 - alpha)
    
    return kappa_precise

def build_graph(graph_type, n):
    """Build adjacency matrix for standard graphs."""
    adj = np.zeros((n, n))
    
    if graph_type == "cycle":
        for i in range(n):
            adj[i][(i+1) % n] = 1
            adj[i][(i-1) % n] = 1
    
    elif graph_type == "complete":
        adj = np.ones((n, n)) - np.eye(n)
    
    elif graph_type == "grid":
        # Square grid
        side = int(np.sqrt(n))
        for i in range(side):
            for j in range(side):
                idx = i * side + j
                if j + 1 < side:
                    adj[idx][idx + 1] = 1
                    adj[idx + 1][idx] = 1
                if i + 1 < side:
                    adj[idx][idx + side] = 1
                    adj[idx + side][idx] = 1
    
    elif graph_type == "star":
        for i in range(1, n):
            adj[0][i] = 1
            adj[i][0] = 1
    
    return adj

# Compute curvatures for different graph topologies
print(f"  {'Graph':<15} {'Nodes':<8} {'Mean Оә':<12} {'ACS interpretation'}")
