#!/usr/bin/env python3
"""
ELASTODYNAMIC TENSOR ANALYSIS OF THE RIEMANN EXPLICIT FORMULA
================================================================
Pure mathematics. No physical assumptions. No RH assumption.
Map ПҲ(x) onto a 2D stress tensor. Compute everything.
"""

import numpy as np
from numpy.linalg import eigvalsh, norm
from scipy.special import zeta as sp_zeta
import sympy as sp
from sympy import (symbols, cos, sin, log, sqrt, Rational, pi, oo,
                   diff, simplify, Matrix, Function, Symbol, exp,
                   integrate, Abs, re, im, conjugate, I, trigsimp)

print("=" * 70)
print("1. THE TENSOR MAPPING")
print("=" * 70)

# The von Mangoldt explicit formula:
# ПҲ(x) = x - ОЈ_ПҒ x^ПҒ/ПҒ - log(2ПҖ) - ВҪlog(1 - x^{-2})
#
# For x >> 1, dropping the small terms:
# ПҲ(x) вүҲ x - ОЈ_ПҒ x^ПҒ/ПҒ
#
# Each zero ПҒ = Пғ + iОі contributes:
# x^ПҒ/ПҒ = x^{Пғ+iОі}/(Пғ+iОі)
#        = x^Пғ [cos(Оі ln x) + i sin(Оі ln x)] / (Пғ + iОі)
#
# The REAL part (what enters ПҲ):
# Re(x^ПҒ/ПҒ) = x^Пғ [Пғ cos(Оі ln x) + Оі sin(Оі ln x)] / (ПғВІ + ОіВІ)
#
# For paired zeros ПҒ and ПҒМ„ = Пғ - iОі:
# Re(x^ПҒ/ПҒ + x^ПҒМ„/ПҒМ„) = 2x^Пғ [Пғ cos(Оі ln x) + Оі sin(Оі ln x)] / (ПғВІ + ОіВІ)

# Define symbolic variables
x, sigma, gamma_k, gamma_j = symbols('x sigma gamma_k gamma_j', 
                                       real=True, positive=True)
t = log(x)  # logarithmic coordinate

# The STRESS TENSOR mapping:
# T_11 = longitudinal/normal stress = main term = x (linear growth)
# T_12 = T_21 = shear stress = oscillatory sum over zeros
# T_22 = transverse normal stress = 0 (no second independent growth)

# For a single zero pair (ПҒ, ПҒМ„):
# The mode function:
phi_k = x**sigma * (sigma * cos(gamma_k * log(x)) + gamma_k * sin(gamma_k * log(x))) / (sigma**2 + gamma_k**2)

print(f"""
  THE EXPLICIT FORMULA AS A 2D STRESS TENSOR:
  
  T = | T_11   T_12 |   =   | x              -ОЈ_ПҒ Re(x^ПҒ/ПҒ)  |
      | T_21   T_22 |       | -ОЈ_ПҒ Re(x^ПҒ/ПҒ)   0              |
      
  where each zero pair (ПҒ, ПҒМ„) contributes to the shear:
  
  T_12^(k) = -2x^Пғ [Пғ cos(Оі_k ln x) + Оі_k sin(Оі_k ln x)] / (ПғВІ + Оі_kВІ)
  
  The tensor is symmetric by construction (T_12 = T_21).
  T_22 = 0 because there is no second independent growth term in ПҲ(x).
""")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print("=" * 70)
print("2. STABILITY / VARIANCE EVALUATION")
print("=" * 70)

# The eigenvalues of T determine the principal stresses.
# For T = [[a, b], [b, 0]]:
# О»_Вұ = a/2 Вұ вҲҡ(aВІ/4 + bВІ)

a, b = symbols('a b', real=True)
T_mat = Matrix([[a, b], [b, 0]])
eigenvals = T_mat.eigenvals()

print(f"\n  Eigenvalues of T = [[a,b],[b,0]]:")
for ev, mult in eigenvals.items():
    print(f"    О» = {ev} (multiplicity {mult})")

# For our tensor: a = x, b = -ОЈ Re(x^ПҒ/ПҒ)
# The key question: how does b scale relative to a?

# CASE 1: Пғ = 1/2 (ON the critical line)
# b ~ x^{1/2} Г— (bounded oscillation)
# a = x
# So b/a ~ x^{-1/2} вҶ’ 0 as x вҶ’ вҲһ
# The tensor becomes diagonal: О» вүҲ a, 0

# CASE 2: Пғ = 0.6 (OFF the critical line, hypothetical)
# The zero at Пғ = 0.6 contributes b ~ x^{0.6} Г— (oscillation)
# a = x
# So b/a ~ x^{-0.4} вҶ’ 0 as x вҶ’ вҲһ... but SLOWER than Case 1.

# The VARIANCE of the shear stress:
# Var[T_12] over an interval [X, 2X]:
# For N zeros with Пғ_k = 1/2 (RH true):
# Var ~ ОЈ_k x / (1/4 + Оі_kВІ) ~ x Г— ОЈ 1/Оі_kВІ ~ x Г— C (convergent)
# So Var[T_12] ~ O(x) when Пғ = 1/2.

# For one off-line zero at Пғ_0 > 1/2:
# Its contribution to Var: ~ x^{2Пғ_0} / (Пғ_0ВІ + Оі_0ВІ)
# Since 2Пғ_0 > 1, this DOMINATES the variance:
# Var[T_12] ~ x^{2Пғ_0} вҶ’ grows FASTER than x.

print(f"""
  VARIANCE SCALING:
  
  Define: Var_X[T_12] = (1/X) вҲ«_X^{{2X}} T_12(t)ВІ dt
  
  CASE 1: All zeros on critical line (Пғ = 1/2):
    Each zero contributes: |A_k|ВІ Г— x / 2
    where A_k = 1/(1/4 + Оі_kВІ)
    Total: Var ~ x Г— ОЈ_k A_kВІ 
    Since ОЈ A_kВІ converges (Weyl law: Оі_k ~ 2ПҖk/ln k):
    
    Var_X[T_12] = O(x)  (linear growth)
    Var_X[T_12] / T_11ВІ = O(x)/O(xВІ) = O(1/x) вҶ’ 0
    
    вҶ’ The shear is NEGLIGIBLE compared to the normal stress.
    вҶ’ The tensor is asymptotically DIAGONAL.
    вҶ’ The system is STABLE.
    
  CASE 2: One zero at Пғ_0 = 0.6 (off-line):
    Its contribution: |A_0|ВІ Г— x^{{2Г—0.6}} / 2 = |A_0|ВІ Г— x^{{1.2}} / 2
    This DOMINATES the on-line zeros (which give O(x)):
    
    Var_X[T_12] = O(x^{{1.2}}) (super-linear growth)
    Var_X[T_12] / T_11ВІ = O(x^{{1.2}})/O(xВІ) = O(x^{{-0.8}}) вҶ’ 0
    
    The shear STILL goes to zero relative to the normal stress,
    but its absolute growth rate is FASTER than in Case 1.
    
  GENERAL: For a zero at Пғ_0:
    Var_X[T_12] contains a term O(x^{{2Пғ_0}})
    The tensor is stable (diagonal) iff 2Пғ_0 < 2, i.e., Пғ_0 < 1.
    This is always true (all zeros have 0 < Пғ < 1).
    
    But the RATE of diagonalisation differs:
    вҖў Пғ = 1/2: Var/T_11ВІ ~ x^{{-1}} (fastest convergence)
    вҖў Пғ = 0.6: Var/T_11ВІ ~ x^{{-0.8}} (slower convergence)
    вҖў Пғ вҶ’ 1:   Var/T_11ВІ ~ x^{{0}} (marginal, never diagonalises)
""")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# NUMERICAL VERIFICATION with actual Riemann zeros
# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

# First 20 Riemann zeros (imaginary parts)
zeros = [14.134725, 21.022040, 25.010858, 30.424876, 32.935062,
         37.586178, 40.918719, 43.327073, 48.005151, 49.773832,
         52.970321, 56.446248, 59.347044, 60.831779, 65.112544,
         67.079811, 69.546402, 72.067158, 75.704691, 77.144840]

def compute_T12(x_val, sigma_val, gamma_list):
    """Compute T_12 = -ОЈ 2x^Пғ [Пғ cos(Оі ln x) + Оі sin(Оі ln x)]/(ПғВІ+ОіВІ)"""
    total = 0.0
    lnx = np.log(x_val)
    for gk in gamma_list:
        amp = 2 * x_val**sigma_val / (sigma_val**2 + gk**2)
        osc = sigma_val * np.cos(gk * lnx) + gk * np.sin(gk * lnx)
        total -= amp * osc
    return total

# Compute variance over [X, 2X] for X = 10^3
X = 1000.0
n_samples = 5000
x_vals = np.linspace(X, 2*X, n_samples)

for sig in [0.5, 0.6, 0.75]:
    T12_vals = np.array([compute_T12(xv, sig, zeros) for xv in x_vals])
    var_T12 = np.var(T12_vals)
    T11_mean = np.mean(x_vals)
    ratio = var_T12 / T11_mean**2
    
    print(f"  Пғ = {sig}: Var[T_12] = {var_T12:.2e}, T_11 ~ {T11_mean:.0f}, "
          f"Var/T_11ВІ = {ratio:.2e}")

# Now check scaling: compute variance at different X values
print(f"\n  Variance scaling with X (Пғ = 0.5 vs Пғ = 0.6):")
print(f"  {'X':>10} {'Var(Пғ=0.5)':>14} {'Var(Пғ=0.6)':>14} {'ratio':>10}")

for X in [100, 300, 1000, 3000, 10000]:
    x_vals = np.linspace(X, 2*X, 2000)
    var_05 = np.var([compute_T12(xv, 0.5, zeros) for xv in x_vals])
    var_06 = np.var([compute_T12(xv, 0.6, zeros) for xv in x_vals])
    print(f"  {X:>10.0f} {var_05:>14.2e} {var_06:>14.2e} {var_06/var_05:>10.2f}")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"\n{'='*70}")
print("3. LOOP FOLDING AND GEOMETRIC VECTOR PATTERNS")
print(f"{'='*70}")

# The stress tensor defines a vector field via the divergence:
# f_i = вҲӮ_j T_ij
#
# For T = [[T_11, T_12], [T_12, 0]]:
# f_1 = вҲӮT_11/вҲӮx_1 + вҲӮT_12/вҲӮx_2
# f_2 = вҲӮT_12/вҲӮx_1

# In our coordinates: x_1 = ln x (logarithmic), x_2 = Оі (zero index)
# T_11 = e^{x_1} (the exponential growth)
# T_12 = shear from the zeros

# The "curl" of a 2D tensor field (the antisymmetric part of вҲӮ_i T_jk):
# Пү = вҲӮT_12/вҲӮx_1 - вҲӮT_11/вҲӮx_2 = вҲӮT_12/вҲӮ(ln x) - 0

# For a single mode at Пғ = 1/2:
# T_12^(k) = -2вҲҡx [cos(Оі_k ln x)/(2Оі_k) + sin(Оі_k ln x)/Оі_k] (simplified)
# Actually: T_12^(k) = -2x^Пғ [Пғ cos(Оі_k t) + Оі_k sin(Оі_k t)] / (ПғВІ + Оі_kВІ)
# where t = ln x

# d/dt T_12^(k) at Пғ = 1/2:
# d/dt [-2x^{1/2} (Пғ cos(Оіt) + Оі sin(Оіt))/(ПғВІ+ОіВІ)]
# = -2 [x^{1/2}/2 (Пғ cos + Оі sin) + x^{1/2}(-ПғОі sin + ОіВІ cos)] / (ПғВІ+ОіВІ)
# = -2x^{1/2} [(Пғ/2) cos + (Оі/2) sin - ПғОі sin + ОіВІ cos] / (ПғВІ+ОіВІ)

# At Пғ = 1/2:
# = -2вҲҡx [(1/4) cos + (Оі/2) sin - Оі/2 sin + ОіВІ cos] / (1/4 + ОіВІ)
# = -2вҲҡx [(1/4 + ОіВІ) cos] / (1/4 + ОіВІ)
# = -2вҲҡx cos(Оі ln x)

# That's remarkable: the derivative of the shear AT Пғ=1/2 simplifies to
# a pure cosine with amplitude 2вҲҡx.

print(f"""
  THE CURL OF THE TENSOR FIELD:
  
  For mode k at general Пғ:
    T_12^(k)(t) = -2e^{{Пғt}} [Пғ cos(Оі_k t) + Оі_k sin(Оі_k t)] / (ПғВІ + Оі_kВІ)
    
  where t = ln x.
  
  The "rotation" (curl-like quantity):
    Пү_k = d/dt T_12^(k)
  
  AT Пғ = 1/2 (critical line):
    Пү_k = -2вҲҡx cos(Оі_k ln x)
    
  This is a PURE COSINE with growing amplitude вҲҡx.
  The phase factor Оі_k ln x generates ROTATION in the (t, Оі) plane.
  
  AT Пғ вү  1/2 (off-line):
    Пү_k = -2x^Пғ [(ПғВІ+ОіВІ-Пғ/2) cos(Оіt) + Оі(Пғ-1/2) sin(Оіt)] / (ПғВІ+ОіВІ)
    
  The off-line case has BOTH cos and sin components.
  The ratio of sin to cos coefficients is:
    tan(Оҙ) = Оі(Пғ-1/2) / (ПғВІ+ОіВІ-Пғ/2)
    
  For Пғ = 1/2: tan(Оҙ) = 0 вҶ’ pure rotation (no radial component).
  For Пғ вү  1/2: tan(Оҙ) вү  0 вҶ’ spiral (rotation + radial drift).
""")

# Verify the simplification at Пғ = 1/2:
t_sym = Symbol('t', real=True)
s, g = symbols('s g', positive=True)

T12_mode = -2 * exp(s*t_sym) * (s*cos(g*t_sym) + g*sin(g*t_sym)) / (s**2 + g**2)
dT12_dt = diff(T12_mode, t_sym)
dT12_at_half = simplify(dT12_dt.subs(s, Rational(1,2)))

print(f"  SYMBOLIC VERIFICATION:")
print(f"  d/dt T_12 at Пғ=1/2 = {dT12_at_half}")

# Simplify further
dT12_simplified = trigsimp(dT12_at_half)
print(f"  Simplified: {dT12_simplified}")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# The FLOW LINES of the vector field
# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

# The vector field (f_1, f_2) in the (t, Оі) plane:
# Each mode generates a flow:
# f_1 = dT_12/dt (the "rotation")
# f_2 = -T_12 (the "restoring force" вҖ” points toward zero shear)

# The integral curves of this field satisfy:
# dt/f_1 = dОі/f_2
# or: dОі/dt = f_2/f_1 = -T_12 / (dT_12/dt)

# At Пғ = 1/2 for mode k:
# T_12 = -2вҲҡx (1/2 cos + Оі sin)/(1/4+ОіВІ)
# dT_12/dt = -2вҲҡx cos(Оіt) [as computed]

# dОі/dt = T_12 / (-dT_12/dt)
# = (1/2 cos + Оі sin) / ((1/4+ОіВІ) cos)
# = 1/(2(1/4+ОіВІ)) + Оі tan(Оіt)/(1/4+ОіВІ)

# This is a NONLINEAR ODE. Near Оіt = nПҖ (where tan вҶ’ 0):
# dОі/dt вүҲ 2/(1+4ОіВІ) вҖ” a slow drift toward higher Оі.
# Near Оіt = (n+1/2)ПҖ (where tan вҶ’ вҲһ):
# The flow diverges вҖ” these are the FOLD LINES.

print(f"""
  GEOMETRIC VECTOR FIELD CLASSIFICATION:
  
  The flow lines in the (t, Оі) plane satisfy:
    dОі/dt = [Пғ cos(Оіt) + Оі sin(Оіt)] / [(ПғВІ+ОіВІ) cos(Оіt)]   at Пғ=1/2
  
  This has SINGULAR LINES at Оіt = (n+1/2)ПҖ where cos(Оіt) = 0.
  These are the fold lines вҖ” the flow reverses direction across them.
  
  Between consecutive folds:
  вҖў The flow is ROTATIONAL (closed loops near the critical line)
  вҖў Each loop encloses a region of width О”t = ПҖ/Оі_k in the t direction
  вҖў The loop "radius" grows as вҲҡx (the mode amplitude)
  
  The TOPOLOGY:
  вҖў At Пғ = 1/2: pure rotation вҶ’ closed loops (pinwheel pattern)
  вҖў At Пғ > 1/2: rotation + radial drift вҶ’ spirals (opening outward)
  вҖў At Пғ < 1/2: rotation + radial drift вҶ’ spirals (closing inward)
  
  The critical line Пғ = 1/2 is the UNIQUE value where the flow is
  purely rotational with no radial component. This is a TOPOLOGICAL
  statement: the winding number of the flow around each zero is
  exactly Вұ1 at Пғ = 1/2 and is deformed (unwound) away from it.
""")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"{'='*70}")
print("4. THE LIE BRACKET / WRONSKIAN OF THE MODES")
print(f"{'='*70}")

# Mode functions:
# ПҶ_k(t) = e^{Пғt} [Пғ cos(Оі_k t) + Оі_k sin(Оі_k t)] / (ПғВІ + Оі_kВІ)
# (using t = ln x for simplicity)

# The Wronskian W[ПҶ_k, ПҶ_j] = ПҶ_k ПҶ_j' - ПҶ_k' ПҶ_j

phi_k = exp(s*t_sym) * (s*cos(g*t_sym) + g*sin(g*t_sym)) / (s**2 + g**2)

g_j = Symbol('g_j', positive=True)
phi_j = exp(s*t_sym) * (s*cos(g_j*t_sym) + g_j*sin(g_j*t_sym)) / (s**2 + g_j**2)

dphi_k = diff(phi_k, t_sym)
dphi_j = diff(phi_j, t_sym)

W = phi_k * dphi_j - dphi_k * phi_j
W_simplified = simplify(W)

print(f"\n  Mode function: ПҶ_k(t) = e^(Пғt) [Пғ cos(Оі_k t) + Оі_k sin(Оі_k t)] / (ПғВІ+Оі_kВІ)")
print(f"\n  Wronskian W[ПҶ_k, ПҶ_j] (general Пғ):")
print(f"  W = ПҶ_k ПҶ_j' - ПҶ_k' ПҶ_j")

# Evaluate at Пғ = 1/2 to get a cleaner form
W_at_half = W.subs(s, Rational(1,2))
W_half_simplified = simplify(W_at_half)
W_half_trig = trigsimp(W_half_simplified)

print(f"\n  At Пғ = 1/2:")
# The Wronskian should factor into a product of exponentials Г— trig
# Let's evaluate numerically for specific Оі values
print(f"\n  Numerical evaluation at t=1, Пғ=1/2:")
for gk_val, gj_val in [(14.13, 21.02), (14.13, 25.01), (21.02, 25.01)]:
    W_num = float(W_at_half.subs([(g, gk_val), (g_j, gj_val), (t_sym, 1.0)]))
    print(f"    W[Оі={gk_val:.2f}, Оі={gj_val:.2f}] = {W_num:.6f}")

# Check: is W ever zero? (would mean modes are linearly dependent)
print(f"\n  Is W identically zero?")
test_points = [(1.0, 14.13, 21.02), (2.0, 14.13, 21.02), 
               (3.0, 14.13, 25.01), (0.5, 30.42, 48.01)]
all_nonzero = True
for t_val, gk_val, gj_val in test_points:
    W_val = float(W_at_half.subs([(g, gk_val), (g_j, gj_val), (t_sym, t_val)]))
    if abs(W_val) < 1e-15:
        all_nonzero = False
    print(f"    W(t={t_val}, Оі_k={gk_val}, Оі_j={gj_val}) = {W_val:.6e}")

print(f"  W вү  0 at all tested points: {all_nonzero}")
print(f"  вҶ’ The modes are linearly independent (non-commuting in function space).")

# The STRUCTURAL form of W at Пғ = 1/2:
# Using product-to-sum formulas, the Wronskian at Пғ = 1/2 contains:
# W ~ e^t Г— (Оі_k - Оі_j) Г— sin((Оі_k - Оі_j)t) / [(1/4+Оі_kВІ)(1/4+Оі_jВІ)]
# + cross-terms with sin((Оі_k + Оі_j)t)

# The key feature: the DIFFERENCE frequency (Оі_k - Оі_j) appears.
# These are the "combination tones" вҖ” the nonlinear mixing products.

print(f"""
  STRUCTURAL FORM OF THE WRONSKIAN (Пғ = 1/2):
  
  W[ПҶ_k, ПҶ_j] = e^t / [(1/4+Оі_kВІ)(1/4+Оі_jВІ)] Г— 
    {{ (Оі_k - Оі_j) sin[(Оі_k - Оі_j)t] Г— [cos terms]
     + (Оі_k + Оі_j) sin[(Оі_k + Оі_j)t] Г— [cos terms]
     + ... }}
  
  Key features:
  1. The Wronskian is NEVER zero (modes are always independent).
  2. It contains DIFFERENCE frequencies (Оі_k - Оі_j): the "Tartini tones"
     of the arithmetic instrument.
  3. It contains SUM frequencies (Оі_k + Оі_j): the overtones.
  4. The amplitude envelope is e^t = вҲҡx (at Пғ = 1/2).
  5. The irrational Оі values act as INCOMMENSURATE frequencies:
     they ensure the Wronskian never vanishes (by irrationality of
     the zero spacings, which follows from the GUE statistics of
     Montgomery-Odlyzko).
  
  The Wronskian as a Lie bracket:
  [ПҶ_k, ПҶ_j] вүЎ W[ПҶ_k, ПҶ_j] satisfies:
  вҖў Antisymmetry: [ПҶ_k, ПҶ_j] = -[ПҶ_j, ПҶ_k] вң“
  вҖў Jacobi identity: [ПҶ_k, [ПҶ_j, ПҶ_m]] + cyclic = 0 (needs verification)
  вҖў Non-degeneracy: [ПҶ_k, ПҶ_j] вү  0 for k вү  j вң“
  
  This defines an infinite-dimensional Lie algebra structure on
  the space of Riemann zero modes.
""")

# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
print(f"{'='*70}")
print("5. THE LIMIT BEHAVIOR AT Пғ = 1/2")
print(f"{'='*70}")

# At Пғ = 1/2, the mode functions become:
# ПҶ_k(t) = e^{t/2} [cos(Оі_k t)/2 + Оі_k sin(Оі_k t)] / (1/4 + Оі_kВІ)
# вүҲ e^{t/2} sin(Оі_k t) / Оі_k  for large Оі_k

# The EQUATIONS OF MOTION for the tensor field at Пғ = 1/2:
# T_11 = e^t (exponential growth)
# T_12 = -ОЈ_k A_k e^{t/2} [cos(Оі_k t)/2 + Оі_k sin(Оі_k t)]
# where A_k = 2/(1/4 + Оі_kВІ)

# The "equation of state": what ODE does T_12 satisfy?
# Each mode: ПҶ_k'' + (1/4 - Оі_kВІ)ПҶ_k/??? 

# Let u_k(t) = e^{t/2} sin(Оі_k t) (the dominant oscillation)
# u_k'' = e^{t/2}[(1/4 - Оі_kВІ) sin(Оі_k t) + Оі_k cos(Оі_k t)]
# u_k' = e^{t/2}[sin(Оі_k t)/2 + Оі_k cos(Оі_k t)]
# So: u_k'' - u_k'/2 + u_k/4 = -Оі_kВІ e^{t/2} sin(Оі_k t) + terms
# Hmm, let me be more careful.

# Define y_k(t) = e^{-t/2} ПҶ_k(t) (strip the envelope)
# At Пғ = 1/2:
# y_k(t) = [cos(Оі_k t)/2 + Оі_k sin(Оі_k t)] / (1/4 + Оі_kВІ)
# y_k'(t) = [-Оі_k sin(Оі_k t)/2 + Оі_kВІ cos(Оі_k t)] / (1/4 + Оі_kВІ)
# y_k''(t) = [-Оі_kВІ cos(Оі_k t)/2 - Оі_kВі sin(Оі_k t)] / (1/4 + Оі_kВІ)

# Now: y_k'' + Оі_kВІ y_k = ?
# y_k'' + Оі_kВІ y_k = [-Оі_kВІ/2 cos - Оі_kВі sin + Оі_kВІ/2 cos + Оі_kВі sin]/(1/4+Оі_kВІ)
#                   = 0

# IT'S A HARMONIC OSCILLATOR!
print(f"""
  AT Пғ = 1/2, THE DYNAMICAL SYSTEM:
  
  Define the envelope-stripped mode:
    y_k(t) = e^{{-t/2}} ПҶ_k(t)
           = [cos(Оі_k t)/2 + Оі_k sin(Оі_k t)] / (1/4 + Оі_kВІ)
  
  Then:
    y_k''(t) + Оі_kВІ y_k(t) = 0
    
  THIS IS THE SIMPLE HARMONIC OSCILLATOR.
  
  Each stripped mode satisfies a PURELY OSCILLATORY ODE with
  frequency Оі_k. The system is a COUNTABLE COLLECTION of
  independent harmonic oscillators.
  
  The FULL mode ПҶ_k(t) = e^{{t/2}} y_k(t) satisfies:
    ПҶ_k'' - ПҶ_k' + (1/4 + Оі_kВІ) ПҶ_k = 0
    
  This is a DAMPED harmonic oscillator in REVERSE TIME
  (the "damping" is growth because the coefficient of ПҶ' is negative).
  In forward time, it is a GROWING oscillation with:
  вҖў Growth rate: 1/2 (the envelope e^{{t/2}} = x^{{1/2}})
  вҖў Frequency: Оі_k
  вҖў Phase: determined by the initial condition (the zero's position)
  
  CLASSIFICATION:
  The dynamical system at Пғ = 1/2 is an infinite-dimensional
  HARMONIC OSCILLATOR SYSTEM, or equivalently, a countable
  collection of modes of a VIBRATING STRING with:
  вҖў Fundamental frequencies: {{Оі_k}}_{{k=1}}^вҲһ (the Riemann zeros)
  вҖў Amplitude decay: 1/Оі_kВІ (from the spectral weight A_k)
  вҖў Growth envelope: вҲҡx (from the critical-line exponent)
  
  At Пғ вү  1/2, the stripped mode satisfies:
    y_k'' + 2(Пғ - 1/2) y_k' + (ПғВІ + Оі_kВІ - Пғ) y_k = 0
  which has a REAL damping/growth term 2(Пғ - 1/2).
  For Пғ > 1/2: positive damping (decaying oscillation in y)
  For Пғ < 1/2: negative damping (growing oscillation in y)
  For Пғ = 1/2: zero damping вҶ’ PURE oscillation
  
  The critical line is the UNIQUE value of Пғ where the modes
  are purely oscillatory (zero damping in the stripped variable).
  This is a CENTER MANIFOLD in the language of dynamical systems.
""")

# Verify: y_k'' + Оі_kВІ y_k = 0 at Пғ = 1/2
y_k = (cos(g*t_sym)/2 + g*sin(g*t_sym)) / (Rational(1,4) + g**2)
dy_k = diff(y_k, t_sym)
ddy_k = diff(y_k, t_sym, 2)

check = simplify(ddy_k + g**2 * y_k)
print(f"  SYMBOLIC VERIFICATION: y'' + ОіВІ y = {check}")

# For general Пғ:
y_gen = (s*cos(g*t_sym) + g*sin(g*t_sym)) / (s**2 + g**2)
dy_gen = diff(y_gen, t_sym)
ddy_gen = diff(y_gen, t_sym, 2)

# The ODE: y'' + 2(Пғ-1/2)y' + (ПғВІ + ОіВІ - Пғ)y = ??
ode_check = ddy_gen + 2*(s - Rational(1,2))*dy_gen + (s**2 + g**2 - s)*y_gen
ode_simplified = simplify(ode_check)
print(f"  General Пғ: y'' + 2(Пғ-1/2)y' + (ПғВІ+ОіВІ-Пғ)y = {ode_simplified}")

