print(f"    ОёвӮӮвӮғ = {theta23_v2:.2f}В° (obs: 49.2В°, gap: {abs(theta23_v2-49.2):.2f}В°)")
print(f"    ОёвӮҒвӮғ = {theta13_v2:.2f}В° (obs: 8.57В°, gap: {abs(theta13_v2-8.57):.2f}В°)")

