# Symbolic computation
# Let k be a null vector in 4D: k = (Пү, Пү, 0, 0) for a photon moving in x
# Torsion trace: T^О»_ОјОҪ = Оҙ^О»_Ој V_ОҪ - Оҙ^О»_ОҪ V_Ој

omega = sp.Symbol('omega', positive=True)
V0, V1, V2, V3 = sp.symbols('V0 V1 V2 V3')

# Null vector k^Ој = (Пү, Пү, 0, 0) вҖ” moving in x direction
k = sp.Matrix([omega, omega, 0, 0])

# Minkowski metric О· = diag(-1, 1, 1, 1)
eta = sp.diag(-1, 1, 1, 1)
V = sp.Matrix([V0, V1, V2, V3])

# Check null: k^Ој k_Ој = О·_ОјОҪ k^Ој k^ОҪ
k_squared = sum(eta[mu,mu] * k[mu]**2 for mu in range(4))
