J2 = (A(0,2) - A(1,3)) / 2
J3 = (A(0,3) + A(1,2)) / 2

# Anti-self-dual (SU(2)_R) generators
K1 = (A(0,1) - A(2,3)) / 2
K2 = (A(0,2) + A(1,3)) / 2
K3 = (A(0,3) - A(1,2)) / 2

